window.__dh_data["te"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "ధమ్మపదం",
  "chaps": "అధ్యాయాలు",
  "fontsize": "అక్షర పరిమాణం",
  "chap1": "యమక వర్గం",
  "1": "ఈనాటి మన జీవితం మన ఆలోచనల ఫలితమే: ఈనాటి మన జీవితమంతా మన ఆలోచనలపై ఆధారపడి, మన ఆలోచనల ద్వారా ఏర్పడింది మాత్రమే. ఒక వ్యక్తి చెడు ఆలోచనతో మాట్లాడినా, ప్రవర్తించినా, బండి చక్రం దానిని లాగుతున్న ఎద్దు డెక్కను అనుసరించినట్లు, బాధ అతన్ని వెంటాడుతుంది.",
  "2": "ఈనాటి మన జీవితం మన ఆలోచనల ఫలితమే: ఈనాటి మన జీవితమంతా మన ఆలోచనలపై ఆధారపడి, మన ఆలోచనల ద్వారా ఏర్పడింది మాత్రమే. ఒక వ్యక్తి స్వచ్ఛమైన ఆలోచనతో మాట్లాడినా, ప్రవర్తించినా, ఆనందం అతన్ని ఎప్పటికీ వదలని నీడలా వెంటాడుతుంది.",
  "3": "'అతను నన్ను దూషించాడు, అతను నన్ను కొట్టాడు, నన్ను జయించి, నన్ను దోచుకున్నాడు,' అలాంటి ఆలోచనలను వ్యక్తం చేసే వారు ప్రతీకార ఉద్దేశ్యం కలిగినవారు, వారిలో ద్వేషం ఆగదు.",
  "4": "'అతను నన్ను దూషించాడు, అతను నన్ను కొట్టాడు, నన్ను జయించి, నన్ను దోచుకున్నాడు,' అటువంటి ఆలోచనలను వ్యక్తం చేయని వారిలో ద్వేషం తగ్గిపోతుంది.",
  "5": "ఈ ప్రపంచంలో ద్వేషంతో శత్రుత్వం ఎప్పుడూ శాంతించదు; ప్రేమ మాత్రమే శత్రుత్వాన్ని శాంతింపజేయగలదు. ఇదే ధర్మం.",
  "6": "ఇది తెలియని చాలా మంది ఈ ప్రపంచంలో మనం ఏదో ఒక రోజు చనిపోతామని కూడా మర్చిపోతారు. వారు తమను తాము నిగ్రహించుకోరు. కానీ ధర్మాన్ని గుర్తించిన వారు తమ గొడవలను త్వరగా ముగించుకుంటారు.",
  "7": "సుఖాలను వెంబడిస్తూ జీవించే వాడు, ఇంద్రియాలు నిగ్రహం లేకుండా జీవించే వాడు, తినే విషయంలో నియంత్రణ లేకుండా ఉండే వాడు, సోమరిపోతు, నిర్వీర్యమైన వాడు - మారా అతన్ని, బలహీనమైన చెట్టును గాలివాన పెకిలించినట్టు పెకిలించివేస్తాడు.",
  "8": "తనను తాను క్రమశిక్షణలో ఉంచుకుంటూ, ఆనందాలను పట్టించుకోకుండా, తన ఇంద్రియాలను నిగ్రహించుకుంటూ, ఆహారంలో మితంగా, విశ్వాసం మరియు నిస్సంకోచమైన శక్తితో ఎవరైతే జీవిస్తాడో - గాలి వానలు పర్వతాన్ని పెకిలించలేని విధంగా, మారా అతన్ని ముట్టుకోలేడు.",
  "9": "అపవిత్రత నుండి విముక్తి లేకుండా, నిగ్రహాన్ని మరియు సత్యాన్ని విస్మరించే వాడు పసుపు వస్త్రానికి (కాషాయ వస్త్రాలు) అర్హుడు కాదు.",
  "10": "నిగ్రహం మరియు సత్యం పట్ల శ్రద్ధ వహించే గుణాలలో బాగా స్థాపితమై, అపవిత్రతలను ప్రక్షాళన చేసిన అతను, పసుపు వస్త్రానికి నిజంగా అర్హుడు.",
  "11": "వినోదభరితమైన, సుఖాలతో నిండిన ఆనంద-భూమిలో జీవించేవారు అసత్యంలో సత్యాన్ని, సత్యంలో అసత్యాన్ని చూస్తూ, వీరు ఎప్పటికీ సత్యాన్నీ గ్రహించలేరు.",
  "12": "సరియైన ఆలోచనా ప్రపంచంలో నివసించే వారు సత్యంలో సత్యాన్ని, అసత్యంలో అసత్యాన్ని చూస్తారు. వారు సత్యానికి చేరుకుంటారు.",
  "13": "పైకప్పు సరిగా లేని ఇంట్లోకి వానలు కురుస్తాయి: సరియైన క్రమశిక్షణ లేని మనస్సులోకి కోరికలు కురుస్తాయి.",
  "14": "పైకప్పు బలంగా ఉన్న ఇంటిలోకి వాన నీరు కురవదు: క్రమశిక్షణతో కూడిన మనస్సులోకి కోరికలు ప్రవేశించవు.",
  "15": "దుర్మార్గుడు ఇహలోకంలో బాధపడతాడు, పరలోకంలో దుఃఖిస్తాడు: అతను రెండింటిలోనూ బాధపడతాడు. బాధలో ఉన్న అతను తన పాపపు పనుల దృశ్యమానంలో దుఃఖిస్తాడు.",
  "16": "సత్పురుషులు ఇహలోకంలో మరియు పరలోకంలో ఆనందిస్తారు; అతను తన స్వచ్ఛమైన పనుల దృశ్యమానంలో చాలా చాలా సంతోషిస్తూ, ఆనందిస్తాడు.",
  "17": "చెడు పనులు చేసే వ్యక్తి వర్తమానంలో మరియు భవిష్యత్తులో పశ్చాత్తాపపడతాడు. 'నేను తప్పు చేశాను' అని తమలో తాము అనుకుంటారు. చెడు ప్రదేశంలో తమను తాము కనుగొన్నప్పుడు వారి బాధలు మరింత పెరుగుతాయి.",
  "18": "మంచి వ్యక్తి ఈ జీవితంలో మరియు తరువాతి జీవితంలో సంతోషంగా ఉంటాడు. 'నేను మంచి చేశాను' అని తమలో తాము అనుకుంటారు. వారు ఆహ్లాదమైన ప్రదేశంలో ఉన్నప్పుడు వారి ఆనందం మరింత పెరుగుతుంది.",
  "19": "పవిత్ర గ్రంథాలను కేవలం పఠిస్తూ, సోమరితనంతో, వాటిని ఆచరణలో పెట్టడానికి ఇష్టపడనివాడు, మరొకరి ఆవులను లెక్కించే కాపరి వంటివాడు. అతను మంచి జీవితం యొక్క ఆశీర్వాదాలను పొందలేడు.",
  "20": "కామం, ద్వేషం మరియు మూర్ఖత్వం విడిచిపెట్టినవాడు, నిజమైన జ్ఞానం మరియు నిర్మలమైన మనస్సును కలిగి ఉంటాడు. ఈ ప్రపంచంలో కానీ ఇంకో ప్రపంచంలో కానీ ఏదీ కోరుకోడు, అతను పఠించే పవిత్ర గ్రంథాల బోధనలను, తక్కువ సంఖ్యలో ఉన్నప్పటికీ, తన జీవితంలో ఆచరిస్తాడు. అలాంటివాడు మంచి జీవితం యొక్క దీవెనలను పాలుపంచుకుంటాడు.",
  "chap2": "అజాగ్రత్త",
  "21": "మోక్షాన్ని పొందేందుకు మెలకువగా ఉండండి. నిర్లక్ష్యం మరణానికి దారి తీస్తుంది. ఆలోచిస్తూ జాగరూకతతో ఉండేవారు నశించరు. అజాగ్రత్తగా ఉన్నవారు ఎప్పుడో మరణించారు.",
  "22": "జ్ఞానులు దీనిని స్పష్టంగా గ్రహిస్తారు, తద్వారా బుద్ధిపూర్వక అవగాహనలో ఆనందాన్ని పొందుతారు. వారు ఆర్యుల వద్ద నివసిస్తూ, జ్ఞానోదయం యొక్క పచ్చిక బయళ్లలో విందు చేస్తారు.",
  "23": "ధ్యానం, పట్టుదల, కృషితో ఎప్పుడూ కష్టపడేవారు, ప్రశాంతంగా.... మోక్షం, విముక్తి మరియు ఆనందం యొక్క అంతిమ స్థితిని సాధిస్తారు.",
  "24": "ఒక వ్యక్తి అప్రమత్తంగా మరియు బుద్ధిపూర్వకంగా ఉన్నప్పుడు, వారి చర్యలు స్వచ్ఛంగా, ఉద్దేశపూర్వకంగా ఉన్నప్పుడు, వారు స్వీయ నియంత్రణను కలిగి, చట్టానికి అనుగుణంగా జీవించినప్పుడు వారి కీర్తి నిరాటంకంగా వర్ధిల్లుతుంది.",
  "25": "ప్రయత్నం, జాగరూకత, క్రమశిక్షణ మరియు స్వీయ-నిగ్రహం ద్వారా, తెలివైన వ్యక్తి తన కోసం ఎలాంటి వరదలకు లోనవని ఒక ద్వీపాన్ని సృష్టించుకుంటాడు.",
  "26": "మూర్ఖులు మరియు అజ్ఞానులు సోమరితనంలో మునిగిపోతారు. జ్ఞానులు అప్రమత్తతను తమ అత్యంత విలువైన సంపదగా భావిస్తారు.",
  "27": "సోమరిగా ఉండవద్దు. కోరికలు మరియు ఇంద్రియ ఆనందాలలో మునిగిపోకుండా ఉండండి. చిత్తశుద్ధితో ధ్యానం చేసేవారు అపారమైన ఆనందాన్ని పొందుతారు.",
  "28": "తెలివైన వ్యక్తి జాగరూకతతో సోమరితనాన్ని అధిగమించినప్పుడు, జ్ఞానం యొక్క శిఖరాగ్రానికి చేరుకుంటాడు. దుఃఖం భారం లేకుండా, వారు ఇతరుల బాధలను గమనిస్తారు. ఎత్తైన శిఖరంపై నిలబడి ఉన్న పర్వతారోహకుడు కింద నిలబడి ఉన్నవారిని చూసినట్టుగా, ఒక జ్ఞాని మూర్ఖులను గమనిస్తాడు.",
  "29": "వేగవంతమైన గుర్రం బలహీనమైనదానిని అధిగమించినట్లు, నిర్లక్ష్యంగా వ్యవహరించే వారిలో, అప్రమత్తమైన వ్యక్తి నిలుస్తాడు. నీరసంగా ఉన్నవారిలో, చురుకైన వ్యక్తి శ్రేష్ఠంగా ఉంటాడు.",
  "30": "అప్రమత్తతతో ఇంద్రుడు దేవతలకు అధిపతిగా ఎదిగాడు. అప్రమత్తత ఎల్లప్పుడూ ప్రశంసించబడుతుంది, అజాగ్రత్త ఎప్పుడూ తిరస్కరించబడుతుంది.",
  "31": "జాగరూకతతో ఆనందించే సన్యాసి, నిర్లక్ష్యం యొక్క ప్రమాదాన్ని గుర్తించి, అడవులను దహించే అగ్నిలా పురోగమిస్తాడు.",
  "32": "జాగరూకతతో ఆనందిస్తూ, అజాగ్రత్త వల్ల కలిగే నష్టాలను అర్థం చేసుకున్న సన్యాసి వెనక్కి తగ్గకుండా, మోక్షానికి దగ్గరగా వస్తాడు.",
  "chap3": "మనస్సు",
  "33": "నిపుణుడైన విలుకాడు బాణాన్ని నిఠారుగా చేసినట్లే, తెలివైన వ్యక్తి వారి వక్రీకృత ఆలోచనలను సరిచేస్తాడు. మనస్సుని కాపాడుకోవడం కష్టం. దీన్ని అదుపు చేయడం కష్టం.",
  "34": "ఒక చేప నీటి నుండి భూమి పై పడినట్లుగా, మారా ప్రభావం నుండి తప్పించుకున్న మనస్సు వణికిపోతోంది.",
  "35": "మన ఆలోచనలను నియంత్రించుకోవడం చాలా కష్టమైన పని. మనసు స్వేచ్ఛగా సంచరిస్తూ, తనకు నచ్చిన చోటికి వెళుతుంది. దానికి క్రమశిక్షణ ఇవ్వడం ప్రయోజనకరం. క్రమశిక్షణతో కూడిన మనస్సు ఆనందాన్ని కలిగిస్తుంది.",
  "36": "తెలివైన వ్యక్తి తన స్వంత ఆలోచనలను గమనించాలి. మనస్సు గుర్తించరాకుండా సూక్ష్మంగా పనిచేస్తుంది. అది కోరుకున్నదానిని పట్టుకుంటుంది. మనసును గమనించడం ద్వారా ఆనందాన్ని పెంపొందించుకోవచ్చు.",
  "37": "తన స్వంత మనస్సును స్వాధీనం చేసుకున్న వ్యక్తి మారా యొక్క నియంత్రణ నుండి విముక్తి పొందుతాడు. మనస్సు అస్పష్టమైనది, స్వతంత్రంగా కదులుతుంది, చాలా దూరం ప్రయాణిస్తుంది మరియు హృదయ లోతుల్లో ఓదార్పుని పొందుతుంది.",
  "38": "నిరంతరం ఉద్రేకపడే వ్యక్తి యొక్క మనస్సులో నిజమైన జ్ఞానం ఉండదు. అలాంటి వ్యక్తి నిజమైన బోధనల గురించి అజ్ఞానంగా ఉంటాడు.",
  "39": "మనస్సు కోరికలతో మండిపోకుండా, ఇష్టాలు మరియు అయిష్టాల నుండి పైకి లేచి వున్న నిర్మలమైన వాడికి భయం ఉండదు. అతను మేల్కొన్నాడు.",
  "40": "శరీరాన్ని మట్టి కుండలాగా పెళుసుగా భావించి, మనసును బలమైన కోటగా గుర్తించి, వివేకం అనే ఆయుధంతో మారాను ఎదుర్కోవాలి. తమ పురోగతిని కాపాడుకుంటూనే, ప్రతికూల శక్తులపై పోరాటాన్ని కొనసాగించాలి.",
  "41": "ఇప్పటికైనా ఎప్పటికైనా, దురదృష్టవశాత్తు, ఈ భౌతిక శరీరం నేలపై పడిపోయి, వదిలివేయబడి, స్పృహ కోల్పోయి, అవగాహన లేకుండా, కాలిపోయిన చెక్క ముక్క వలె పనికి రాకుండా పోతుంది.",
  "42": "ఒక శత్రువు తన శత్రువుకు కలిగించే హాని కంటే, ఒక ద్వేషి తాను ద్వేషించే వానికి చేసే హాని కంటే, తప్పుగా నిర్దేశించబడిన మనస్సు మనకు ఎక్కువ హాని చేస్తుంది.",
  "43": "తల్లి కన్నా, తండ్రి కన్నా, ఎంతటి బంధువులకన్నా; ఒక మంచి మనస్సు మనకు గొప్ప సేవ చేస్తుంది.",
  "chap4": "పువ్వులు",
  "44": "భూలోకాన్ని ఎవరు జయించగలరు? యముడు పాలించే మృత్యు రాజ్యాన్ని ఎవరు అధిగమించగలరు? దేవతల యొక్క ఆనంద రాజ్యాన్ని ఎవరు పొందగలరు? నైపుణ్యం కలిగిన తోటమాలి ఉత్తమమైన పువ్వులను ఎంచుకున్నట్లుగా ఎవరు ధర్మ మార్గంలో నడపగలరు?",
  "45": "శిష్యుడు, అంకితభావం కలిగిన అభ్యాసకుడు, ఈ భూమిని జయించగలడు. వాడు మృత్యు రాజ్యాన్ని అధిగమించి దేవతల రాజ్యాన్ని పొందగలరు. నైపుణ్యం కలిగిన తోటమాలి చాలా అందమైన పువ్వులను ఎంచుకున్నట్లే, శిష్యుడు న్యాయ మార్గంలో నడవడానికి ఎంచుకుంటాడు.",
  "46": "ఈ భౌతిక శరీరం నురుగులాగా క్షణికమైనదని, ఎండమావిలాగా భ్రమ అని తెలుసుకుని, మారా యొక్క ప్రలోభాలకు గురిచేసే వలల నుండి విముక్తి పొందుతూ, శిష్యుడు జీవన్మరణ చక్రాన్ని తాకకుండానే దాటిపోతాడు.",
  "47": "నిద్రలో ఉన్న పల్లెను వరద కొట్టుకుపోయినట్లే, ఇంద్రియ సుఖాలలో మునిగితేలడంపై మనస్సు స్థిరపడిన వారిని మృత్యువు కొట్టి పారేస్తుంది.",
  "48": "ఇంద్రియ సుఖాలను కోరుకునే వారిని, వారు తమ కోరికలను పూర్తిగా తీర్చుకోకముందే మరణం అధిగమిస్తుంది.",
  "49": "ఒక తేనెటీగ పువ్వు యొక్క సువాసన, రంగును గాయపరచకుండా తేనెను సేకరించినట్టు, ముని తన జీవితాన్ని గడపాలి.",
  "50": "ఇతరుల అనర్హమైన చర్యలు, పాపాలు, లోపాలపై దృష్టి పెట్టే బదులు, ఒకరు తమ స్వంత పాప లోపాలను ప్రతిబింబించాలి.",
  "51": "పనికిమాలిన మధురమైన పదాలు సువాసన లేని రంగురంగుల పువ్వుల వంటివి.",
  "52": "కానీ సరసమైన, ఫలవంతమైన, సానుకూల చర్యలకు దారితీసే పదాలు, రంగు మరియు సువాసనతో నిండిన అందమైన పువ్వుల వంటివి.",
  "53": "పువ్వుల కుప్ప నుండి వివిధ రకాల దండలు తయారు చేయబడినట్లుగా, ఒక మామూలు జీవి తన జీవితాంతం అనేక మంచి పనులను కూడగట్టుకుంటుంది.",
  "54": "పూల సువాసన గాలికి ఎదురుగా వెళ్లదు. మంచితనం యొక్క సువాసన గాలికి వ్యతిరేకంగా ప్రయాణించగలదు. సద్గురువు యొక్క సువాసన వారి చర్యలన్నిటిలోనూ వ్యాపిస్తుంది.",
  "55": "గంధం, కమలం, తామర, వస్సికి పరిమళాలను కూడా మించిన సువాసన ధర్మం యొక్క సువాసన.",
  "56": "గంధం, కమలం, తామర, వస్సికి పరిమళాలను మించి, సద్గురువుల పరిమళం దేవతల ఔన్నత్యాన్ని అధిరోహిస్తుంది.",
  "57": "నిజమైన సద్గుణాన్ని కలిగి ఉన్నవారికి, జాగరూకతతో ఉన్నవారికి, పరిపూర్ణమైన జ్ఞానంతో విముక్తి పొందినవారికి మారా ఎటువంటి హాని చేకూర్చలేదు.",
  "58": "రోడ్డు పక్కన ఉన్న చెత్త కుప్ప నుండి కలువ పువ్వులు, సువాసనగా, ఆహ్లాదకరంగా వెలువరిస్తాయి.",
  "59": "అదేవిధంగా, అంధుల సమూహం నుండి, నిజమైన జ్ఞానులు ఉద్భవించి, జ్ఞానం యొక్క ప్రకాశంతో ప్రకాశిస్తారు.",
  "chap5": "మూర్ఖులు",
  "60": "నిద్రలేని వ్యక్తికి, రాత్రి చాలా పొడవుగా అనిపిస్తుంది. అలసిపోయిన వారికి, పది మైళ్ల దూరం చాలా ఎక్కువ అనిపిస్తుంది. ధర్మం గురించి తెలియని మూర్ఖులకు పుట్టుక, మరణాల గొలుసు చాలా పొడవుగా ఉంటుంది.",
  "61": "ప్రయాణికుడికి, తనకు సమానమైన లేదా తమను మించిన సహచరుడు దొరకకపోతే, ఒంటరిగా ప్రయాణం కొనసాగించడం మంచిది. మూర్ఖునితో సాంగత్యము ఎట్టి పరిస్థితుల్లో చేయరాదు.",
  "62": "మూర్ఖుడు తన ఆస్తి గురించి చింతిస్తూ, 'నాకు కొడుకులు ఉన్నారు, నాకు సంపద ఉంది.' కానీ అతను కూడా తనకి సొంతం కాదు. కాబట్టి అతనికి కొడుకులు ఎలా ఉంటారు? అతనికి సంపద ఎలా ఉంటుంది?",
  "63": "తన తెలివితక్కువతనాన్ని గ్రహించే మూర్ఖుడు అంత మేరకు తెలివైనవాడు, కానీ తనను తాను జ్ఞాని అని నమ్మే మూర్ఖుడు నిజమైన మూర్ఖుడు.",
  "64": "ఒక చెంచా, సూప్ యొక్క రుచి చూడనట్లే, తన జీవితమంతా తెలివైన వ్యక్తితో గడిపిన మూర్ఖుడు సత్యాన్ని చూడలేడు.",
  "65": "అయితే, తెలివైన వ్యక్తితో సహవాసం చేసే ఆలోచనాపరుడు, నాలుక, సూప్రుచిని ఆస్వాదించినట్లే సత్యాన్ని త్వరగా అర్థం చేసుకుంటాడు.",
  "66": "అవగాహన లేని మూర్ఖులు తమకు తాము శత్రువులుగా మారతారు, ఎందుకంటే వారి చెడు పనులు తిరిగి వారికే చేదు పరిణామాలను కలిగిస్తాయి.",
  "67": "చెడు పనులకు సరిపడా పశ్చాత్తాపం వెనకే వస్తుంది; దుఃఖంతో మరియు కన్నీళ్లతో మనిషి దాని పరిణామాలను పొందుతాడు.",
  "68": "మంచి కార్యాలను పశ్చాత్తాపం వెంటాడదు; ఆనందంతో మనిషి దాని పరిణామాలను పొందుతాడు.",
  "69": "చెడ్డ పని ఫలించనంత కాలం, మూర్ఖుడు దానిని తేనెలాగా తీపిగా ఉందని భావిస్తాడు. కానీ అది ఫలించినప్పుడు, మూర్ఖుడు దుఃఖానికి గురవుతాడు.",
  "70": "ఒక మూర్ఖుడు నెలల తరబడి తన ఆహారాన్ని కుశ-గడ్డి పరకతో తిన్నంత మాత్రాన, బోధలను నిజంగా అర్థం చేసుకున్న వారిలో పదహారవ వంతు కూడా విలువైనవాడు కాదు.",
  "71": "అప్పుడే పితికిన పాలు ఎలాగైతే పగలవో, చెడు పనులు వెంటనే ప్రభావం చూపవు. అది బూడిద కింద దాగిన నిప్పులా పొగలు కక్కుతూ, మూర్ఖుడిని కాల్చివేస్తుంది.",
  "72": "మూర్ఖుడు ఎటువంటి జ్ఞానాన్ని సంపాదించినా అతనికి ప్రయోజనం లేదు. ఇది అతను గతంలో కలిగి ఉన్న యోగ్యతను దెబ్బతీసి, వర్తమానంలో అతని చర్యలను గందరగోళానికి గురిచేస్తుంది.",
  "73": "మూర్ఖుడిని, తప్పుడు ఖ్యాతి కోరుకోనివ్వండి. ప్రాధాన్యత కోసం, కాన్వెంట్లలో, ప్రభువుత్వం మరియు ప్రజలందరి నుండి ఆరాధనను కోరుకోనివ్వండి.",
  "74": "'ఇది నేనే చేశానని గృహస్థులు, సన్యాసులు అనుకోవాలి. ఏమి చేయాలి మరియు ఏమి చేయకూడదు అనే విషయంలో వారు నా ఇష్టాన్ని అనుసరించాలి.' మూర్ఖుని కోరిక అలాంటిది. ఈ విధంగా అతని కోరిక మరియు గర్వం పెరుగుతాయి.",
  "75": "ఒకటి ప్రాపంచిక లాభాలకు దారితీసే మార్గం; మరొకటి మోక్షానికి దారితీసే మార్గం. బుద్ధుని అనుచరుడైన భిక్షువు దీనిని నేర్చుకొని, ప్రాపంచిక ప్రశంసలను కోరుకోకుండా, వివేకం కోసం ప్రయత్నించాలి.",
  "chap6": "జ్ఞానులు",
  "76": "తప్పులను గుర్తించి, నిందకు అర్హమైన వాటిని విమర్శించే తెలివైన వ్యక్తి మీకు కనిపిస్తే, ఆ జ్ఞానిని అనుసరించండి. దాచిన నిధిని బహిర్గతం చేసే వ్యక్తిగా అతనికి విలువ ఇవ్వండి.",
  "77": "అతను మంచివారికి ప్రియమైనవాడు; చెడ్డ వారు అతన్ని అసహ్యించుకుంటారు. అలాంటి వ్యక్తిని మార్గనిర్దేశం చేయనివ్వండి, బోధించనివ్వండి, తన వద్ద, సరికాని ప్రవర్తన ఏంటో తెలుసుకోండి.",
  "78": "తప్పు చేసే వారితో లేదా నీచమైన వ్యక్తులతో స్నేహం చేయవద్దు. బదులుగా, మంచి వారితో స్నేహం చేయండి. ఉత్తమ వ్యక్తులతో సహవాసం చేయండి.",
  "79": "ప్రశాంతంగా ధర్మ బోధలను గ్రహించేవారు ఆనందంగా జీవిస్తారు. జ్ఞానులు జ్ఞానోదయం పొందిన వారి గొప్ప బోధనలలో ఆనందాన్ని పొందుతారు.",
  "80": "శిల్పకారులు శిల్పాలను చెక్కుతారు. బాణాలు నైపుణ్యం కలిగిన కళాకారులు రూపొందిస్తారు. చెక్కను వడ్రంగులు తయారు చేస్తారు. అలాగే, తెలివైన వ్యక్తులు తమను తాము క్రమశిక్షణలో పెట్టుకుంటారు.",
  "81": "తుఫాను ఎదురైనప్పుడు బండ రాయి కదలకుండా ఉంటుంది. జ్ఞానిని ప్రశంసలు లేదా నిందలు కదిలించలేవు.",
  "82": "ధర్మం వినగానే, జ్ఞానులు, స్పష్టంగా ఉన్న లోతైన సరస్సులా ప్రశాంతంగా మారతారు.",
  "83": "మంచి వ్యక్తులు ఏది జరిగినా ముందుకు సాగుతూ వెళతారు. వారు కబుర్లు చెప్పుకోరు, ఆనందాల కోసం ఆరాటపడరు. జ్ఞానులు సంతోషంతో ఉప్పొంగి పోరు, దుఃఖం తాకినప్పుడు కృంగిపోరు.",
  "84": "జ్ఞాని తన కోసం కానీ, ఇతరుల కోసం కానీ కుమారులను, సంపదను, హోదాను కోరుకోడు.",
  "85": "కొద్దిమంది మాత్రమే సుదూర తీరానికి చేరుకోగలుగుతారు. చాలా మంది ప్రజలు ఈ సంసారం లో తమ ప్రస్థానాన్ని కొనసాగిస్తారు.",
  "86": "బోధనలు వింటూ, దాని సూత్రాలకు కట్టుబడి ఉన్నవారు అవతలి వైపుకు వెళతారు. మారా యొక్క ఆధిపత్యమైన ఈ సముద్రం నిజంగా సవాలుతో కూడుకున్నది.",
  "87": "మనిషిని, ఒప్పుకోవడం కష్టమైనప్పటికీ, 'ఏకాంతం' విలువైనదిగా భావించనివ్వండి. వారు గృహస్థుని జీవితాన్ని త్యజించి, నిరాశ్రయుల మార్గాన్ని వెతకనివ్వండి. బుద్ధిమంతులు చీకటి మార్గాలను విడిచిపెట్టి కాంతి మార్గాన్ని అనుసరించాలి.",
  "88": "ఇంద్రియ సుఖాలన్నింటినీ విడిచిపెట్టి, ఏదీ తమ సొంతమని భావించకుండా, జ్ఞానవంతుడు తన హృదయాన్ని అన్ని మలినాలనుండి శుద్ధి చేసి, నిజమైన ఆనందాన్ని పొందుతాడు.",
  "89": "ఈ లోకంలో జీవిస్తూ, తమ కోరికలను జయించిన వారు, జ్ఞానోదయం యొక్క మూలకాలలో మనస్సును కలిగి ఉన్నవారు, నిర్లిప్తతా స్వేచ్ఛను స్వీకరించడం తప్ప దేనికీ కట్టుబడని వారు, మోక్షం యొక్క ఆనందాన్ని పొందుతాడు.",
  "chap7": "మోక్ష ప్రాప్తి లభించిన వారు",
  "90": "అన్ని బంధాల నుండి విముక్తి పొంది, అన్ని విధాలుగా ముక్తిని సాధించినవాడు దుఃఖానికి దూరమైనా వాడు. అలంటి వారు బాధలను అనుభవించరు; వారి ప్రయాణం పూర్తయింది.",
  "91": "బుద్ధిమంతులు శ్రద్ధగా పనిచేస్తారు. వారు ఏ నివాసంలోనూ ఆనందాన్ని పొందలేరు. హంసలు తమ సరస్సులను విడిచిపెట్టినట్లు వారు తమ ఇళ్లను విడిచిపెడతారు.",
  "92": "ఆస్తులు లేనివారు, జ్ఞానానికి అనుగుణంగా తమను తాము పోషించుకునేవారు, జీవితం శూన్యం మరియు క్షణికమైనదని గ్రహించి, స్వేచ్ఛ యొక్క లక్ష్యాన్ని గ్రహించేవారు, ఆకాశంలో ఎగురుతున్న పక్షుల వలె వారి మార్గం గుర్తించడం కష్టం.",
  "93": "కోరికలు నశించి, ఆహారం పట్ల ఉదాసీనంగా ఉండి, జీవితం శూన్యమని మరియు అశాశ్వతమని గ్రహించిన వ్యక్తి, ఆకాశంలో ఎగురుతున్న పక్షుల వలె వారి మార్గాన్ని సులభంగా గుర్తించలేము.",
  "94": "రథసారథి ద్వారా చక్కగా మచ్చిక చేసుకున్న గుర్రాల వలె, ఇంద్రియాలను అదుపులో ఉంచుకున్న వారిని దేవతలు కూడా మెచ్చుకుంటారు. వారు అహంకారం మరియు దుష్టత్వం నుండి విముక్తి పొందినవారు.",
  "95": "భూమివంటి ఓపిక, ఇంద్రుని పిడుగులాంటి దృఢత్వం, బురద లేని సరస్సు వంటి నిర్మలత్వం కలిగిన వానికి జనన మరణ చక్రం ఉండదు.",
  "96": "ఆలోచనలో ప్రశాంతత, వాక్కులో ప్రశాంతత, క్రియల్లో ప్రశాంతత ఉన్నవారే నిజమైన జ్ఞానం ద్వారా స్వాతంత్య్రాన్ని పొందుతారు. వారు నిర్మలంగా మారి ప్రశాంతతతో నిండి ఉన్నారు.",
  "97": "విశ్వాసాలకు తేలికగా లొంగని వారు, అన్ని అనుబంధాలను, కోరికలను తుడిచిపెట్టి, ఇష్టాయిష్టాల భావాలు తలెత్తకుండా, శాశ్వతమై వాస్తవాన్ని తెలిసిన వారు, మానవులలో నిజంగా ఉన్నతమైనవారు.",
  "98": "అరహతులు నివసించే ప్రదేశాలు, గ్రామాల్లో కానీ, అడవుల్లో కానీ, లోతైన జలాలలో కానీ, ఎడారి అంచుల్లోకాని, ఎంతో ఆహ్లాదకరంగా ఉంటాయి.",
  "99": "అరణ్యాలు అర్హతులకు ఆహ్లాదకరంగా ఉంటాయి, ప్రపంచీకులను అడవులు ఆకర్షించవు. కామ క్రోధాలను అధిగమించిన వారు, ఇంద్రియ భోగాలచే మోహింపబడనందున అక్కడ ఆనందాన్ని పొందుతారు.",
  "chap8": "వెయ్యిలు",
  "100": "శాంతి కలిగించే ఒక్క అర్ధవంతమైన వాక్యం వెయ్యి పదాల ఖాళీ ప్రసంగం కంటే ఎంతో మంచిది.",
  "101": "ఖాళీ పదాల వెయ్యి శ్లోకాల కంటే శాంతిని కలిగించే ఒక్క చరణం మేలు.",
  "102": "వంద శూన్య శ్లోకాలు పఠించడం కంటే శాంతిని కలిగించే ఒక చరణాన్ని పునరావృతం చేయడం మంచిది.",
  "103": "యుద్ధాలలో వెయ్యి సార్లు వెయ్యి మందిని జయించిన వ్యక్తి కంటే తనను తాను జయించిన వాడు ఉత్తముడు. అతను నిజంగా యోధులలో అత్యంత శక్తివంతమైనవాడు.",
  "104": "ఇతరులపై విజయం కంటే తమపై విజయం సాధించడం గొప్ప పని. ఎప్పుడూ ఆత్మనిగ్రహం పాటించే వానిని",
  "105": "దేవతలు, గంధర్వులు, బ్రహ్మ దేవుడూ మరియు మారా కూడా ఓడించలేరు.",
  "106": "వంద సంవత్సరాల పాటు నెల నెలా, వెయ్యి త్యాగాలు అర్పించే వ్యక్తి కంటే, జ్ఞానంతో కూడిన వ్యక్తికి నివాళులు అర్పించే వ్యక్తి ఉత్తమం. శతాబ్దాల అధికారిక త్యాగాల కంటే ఆ నివాళి ఉన్నతమైనది.",
  "107": "వంద సంవత్సరాలు అడవిలో పవిత్రమైన అగ్నిని సంరక్షించే వ్యక్తి కంటే జ్ఞానంతో కూడిన వ్యక్తికి నివాళులు అర్పించే వ్యక్తి ఉత్తమం. శతాబ్దాల అధికారిక త్యాగాల కంటే ఆ నివాళి ఉన్నతమైనది.",
  "108": "పుణ్యం కోసం ఏడాది పొడవునా నైవేద్యాలు, బలి అర్పించే వ్యక్తి కంటే సజ్జనులకు సన్మానం చేసేవాడు మేలు. ఇతని విలువలో పావు వంతు కూడా మిగిలినవారిది ఉండదు.",
  "109": "పెద్దలను గౌరవిస్తూ భక్తిని పాటించే వ్యక్తికి నాలుగు వరాలు - దీర్ఘమైన రోజులు, అందం, ఆనందం మరియు బలం.",
  "110": "అధర్మంతో, గాలికి బ్రతికే వంద సంవత్సరాల జీవితం కంటే, ధ్యానం చేసే సద్గురువు యొక్క జీవితం ఒక్క రోజు జీవించడం ఉత్తమం.",
  "111": "బుద్ధిలేకుండా, స్థిరత్వం లేని వంద సంవత్సరాల జీవితం కంటే, వివేకంతో ధ్యానం చేసే వ్యక్తిలా ఒక్క రోజు జీవించడం ఉత్తమం.",
  "112": "నిష్క్రియమైన, బలహీనమైన వంద సంవత్సరాల జీవితం కంటే, కష్టపడి ప్రయత్నించే వ్యక్తిలా ఒక్క రోజు జీవించడం ఉత్తమం.",
  "113": "వస్తువుల మూలాన్ని, అంతాన్ని గ్రహించని వ్యక్తి యొక్క వంద సంవత్సరాల జీవితం కంటే, వస్తువుల మూలాన్ని, ముగింపును గ్రహించిన వ్యక్తిలా ఒక్క రోజు జీవించడం ఉత్తమం.",
  "114": "మరణం లేని స్థితిని గ్రహించని వ్యక్తి యొక్క వంద సంవత్సరాల జీవితం కంటే, ఆ మరణం లేని స్థితిని గ్రహించిన వ్యక్తి యొక్క ఒక్క రోజు జీవితం మంచిది.",
  "115": "అత్యున్నతమైన ధర్మాన్ని గ్రహించని వ్యక్తి యొక్క వంద సంవత్సరాల జీవితం కంటే, అత్యంత అద్భుతమైన సిద్ధాంతాన్ని గ్రహించిన వ్యక్తి యొక్క స్వల్ప జీవితం ఉత్తమం.",
  "chap9": "దుర్మార్గం",
  "116": "మనిషి మంచి వైపు తొందరపడాలి; అతను తన చెడు ఆలోచనలను అరికట్టాలి; అతను మంచి చేయడంలో అలసత్వం వహిస్తే, అతని మనస్సు చెడు వైపు మొగ్గు చూపుతుంది.",
  "117": "ఎవరైనా పాపం చేస్తే ఆ మార్గంలో కొనసాగనివ్వకండి. వారు తమ హృదయాన్ని దానిపై స్థిరపరచనివ్వకండి. పాప కార్యాల సంచితం బాధకు దారితీస్తుంది.",
  "118": "మనుష్యుడు మంచిపని చేస్తే మరల మరల చేయనివ్వండి. అతను తన మనస్సును దానిపై కేంద్రీకరించాలి. పుణ్య కార్యాలు ఆనందానికి దారి తీస్తాయి.",
  "119": "దుర్మార్గుడు కూడా తన పాపాలు పండనంత కాలం ఆనందాన్ని చూస్తాడు; కానీ అతని పాపాలు పండినప్పుడు, పాపికి కష్టాలు వాటిల్లుతాయి.",
  "120": "ఒక మంచి మనిషి, బహుశా, అతని మంచి పనులు పండనంత కాలం చెడును అనుభవిస్తాడు; కానీ అతని పుణ్య కార్యాలు పండినప్పుడు, అతను మంచిని గ్రహిస్తాడు.",
  "121": "చెడు గురించి తేలికగా, 'అది నా దగ్గరకు రాదు,' అని ఆలోచించకండి. నీటి కుండ కూడా నిరంతరం పడే నీటి చుక్కలతో నిండిపోతుంది. మూర్ఖుడు తన పాపాలను కొద్దికొద్దిగా కూడగట్టుకుంటూ చెడుతో నిండిపోతాడు.",
  "122": "'అది నాకు రాదు' అని అనుకుని మంచి గురించి తేలికగా ఆలోచించవద్దు. నీటి కుండ కూడా నిరంతరం పడే నీటి బిందువుల మూలాన నిండిపోతుంది. జ్ఞానవంతుడు కొద్దికొద్దిగా పుణ్యాలను కూడబెట్టుకున్నప్పుడు, మంచితనంతో నిండిపోతాడు.",
  "123": "సంపన్నుడైన వ్యాపారి ప్రమాదకరమైన మార్గాలను తప్పించుకున్నట్లే, ప్రాణానికి విలువ ఇచ్చే వ్యక్తి విషాన్ని దూరం పెట్టినట్లే, ఒకడు చెడును నివారించాలి.",
  "124": "చేతికి గాయం లేనివాడు విషాన్ని తాకవచ్చు. గాయం లేనివాడికి విషం హాని చేయదు. చెడు చేయని వానికి చెడు జరగదు.",
  "125": "గాలికి విసిరిన మెత్తటి ధూళి తిరిగి విసిరిన వాడి మొహాన పడినట్లే, అమాయకుడికి, స్వచ్ఛమైన పుణ్యాత్ముడికి హాని కలిగించే వ్యక్తికి, హాని తిరిగి వస్తుంది.",
  "126": "కొంతమంది తిరిగి గర్భంలోకి ప్రవేశిస్తారు; దుర్మార్గులు నరకాన్ని అనుభవిస్తారు; మంచివారు స్వర్గానికి వెళతారు, ప్రాపంచిక కోరికల నుండి విముక్తి పొందిన వారు మోక్షాన్ని పొందుతారు.",
  "127": "ఆకాశంలో కానీ, సముద్రపు లోతుల్లో కానీ, పర్వతాల కోనల్లో కానీ, భూమిపై ఎక్కడా కూడా ఒక పాపి తన కర్మ సంస్కారాల నుండి తప్పించుకోలేడు.",
  "128": "ఆకాశంలో కానీ, సముద్రపు లోతుల్లో కానీ, పర్వతాల కోనల్లో కానీ, భూమిపై ఎక్కడా కూడా ఒక మనిషి తన మరణాన్ని తప్పించుకోలేడు.",
  "chap10": "కర్ర",
  "129": "మనుష్యులందరూ కర్రను చూసి వణుకుతారు, మనుషులందరూ మరణానికి భయపడతారు. మరొకరి స్థానంలో తనను తాను ఉంచుకుని, మరొకరిని చంపడం కానీ, వారి చావుకు కారణం కానీ కాకూడదు.",
  "130": "మనుష్యులందరూ కర్రను చూసి వణుకుతారు; మనుషులందరికీ ప్రాణం ప్రియమైనది. మరొకరి స్థానంలో తనను తాను ఉంచుకుని, మరొకరిని చంపడం కానీ, వారి చావుకు కారణం కానీ కాకూడదు.",
  "131": "తన సంతోషాన్ని కోరుకుంటూ, తన సంతోషం కోసం ఇతరులను కర్రతో శిక్షించే వాడు, మరణానంతరం ఆనందాన్ని పొందలేడు.",
  "132": "తన సంతోషాన్ని కోరుకుంటూ, తన సంతోషం కోసం ఇతరులను కర్రతో శిక్షించనివాడు, మరణానంతరం ఆనందాన్ని పొందుతారు.",
  "133": "ఎవరితోనూ కఠినంగా మాట్లాడకు; అలా మాట్లాడిన వారు ప్రతీకారం తీర్చుకుంటారు. కోపంతో మాట్లాడటం బాధాకరమైనది కాబట్టి, ప్రతీకార కర్ర మిమ్మల్ని అధిగమించవచ్చు.",
  "134": "విరిగిన గంట లాగా మిమ్మల్ని మీరు కుదురుగా మార్చుకున్నప్పుడు మీరు మోక్షాన్ని చేరుకున్నట్టే, ఎందుకంటే మీలో కోపం లేదు.",
  "135": "గోవుల కాపరి తన కర్రతో ఆవులను పచ్చిక బయళ్లలోకి నడిపించినట్లు, వృద్ధాప్యం మరియు మరణం మనుషులను కొత్త జీవనం వైపు తరిమికొడతాయి.",
  "136": "చెడు చేస్తున్న మూర్ఖుడికి తన మూర్ఖత్వం తెలియదు. అతని స్వంత పనులు, అగ్నిలాగా, అతన్ని కాల్చేస్తాయి.",
  "137": "హాని చేయలేని అమాయకుడను కించపరిచే వ్యక్తి ఈ పది స్థితులలో ఒకదానికి త్వరలోనే చేరుకుంటాడు:",
  "138": "అతను తీవ్రమైన నొప్పి, లేదా వ్యాధి, లేదా శరీర క్షయం, బాధాకరమైన విప్పత్తు, మతి చెడిపోవడం,",
  "139": "లేదా రాజు యొక్క అసంతృప్తి, లేదా అపకీర్తి, లేదా సంబంధాలు కోల్పోవడం, లేదా అతని సంపదనంతటినీ కోల్పోవడం,",
  "140": "లేదా పిడుగుపడి లేదా అగ్నిప్రమాదంతో అతని ఇల్లు నాశనం కావడం. మరణం వద్ద, ఈ మూర్ఖుడు, దుఃఖంలో పునర్జన్మను కనుగొంటాడు.",
  "141": "నగ్నత్వం కాదు, జడలు కట్టిన జుట్టు కాదు, అపరిశుభ్రత, ఉపవాసం, నేలపై పడుకోవడం, శరీరాన్ని దుమ్ము మరియు బూడిదతో కప్పడం, లేదా భంగిమలో కూర్చోవడం వంటివి ఏవీ, సందేహాలతో నిండిన మానవుడిని శుభ్రపరచవు.",
  "142": "అయితే ప్రశాంతంగా, నిర్మలంగా ఉండి, పవిత్రమైన, సంయమనంతో కూడిన జీవితాన్ని గడుపుతూ, జీవులకు హాని కలిగించడం మానేసిన వాడు, గొప్ప వేషధారణతో ఉన్నప్పటికీ, అతడు బ్రాహ్మణుడు, సన్యాసి, సాధువు మరియు భిక్షువు.",
  "143": "ఈ ప్రపంచంలో, కొరడా తాకినప్పుడు రేసు గుర్రానికి వాత పడనట్టుగా, వినయపూర్వకంగా, విమర్శలకు ఇబ్బంది పడని వ్యక్తి ఉన్నాడా?",
  "144": "కొరడాతో తాకిన గుర్రంలా, మనిషిని ఉత్సాహంగా, చురుకుగా ఉండనివ్వండి. విశ్వాసం మరియు ధర్మం ద్వారా, శక్తి మరియు మనస్సు ద్వారా, చట్టం యొక్క వివేచన ద్వారా, జ్ఞానం, సత్ప్రవర్తన, ఏకాగ్రతతో, అతను భూసంబంధమైన గొప్ప దుఃఖాన్ని కొట్టివేస్తాడు.",
  "145": "నీటిపారుదల శాఖ నీటిని నడిపించినట్లే, బాణాలను నిఠారుగా మార్చినట్లు, వడ్రంగులు చెక్కను చెక్కినట్లే, మంచి వ్యక్తులు తమను తాము క్రమశిక్షణలో ఉంచుకుంటారు.",
  "chap11": "ముసలితనం",
  "146": "ఈ ప్రపంచం అంధకారంలో మండిపోతుంటే నువ్వు ఎందుకు నవ్వుతున్నావు, సంతోషిస్తున్నావు? బదులుగా కాంతిని ఎందుకు వెతకట్లేదు?",
  "147": "పుండ్లు, పెళుసుదనం మరియు క్షణికావేశంతో నిండి, దెగ్గరగా అతుక్కొని, రోగాలతో, వచ్చి పోయే ఆలోచనలతో, చిత్రం లాంటి ఈ శరీరాన్ని చూడండి.",
  "148": "ఈ శరీరం అరిగిపోతోంది; ఇది రోగాల గూడు; ఇది బలహీనంగా ఉంది. ఈ అవినీతి కుప్ప ముక్కలవుతోంది. జీవితం మరణంతో ముగుస్తుంది.",
  "149": "శరదృతువులో పారవేయబడిన పొట్లకాయలా తెల్లబడిన ఈ ఎముకలను చూడటంలో ఏమి ఆనందం ఉంది?",
  "150": "ఈ ఎముకల నుండి ఒక కోట తయారు చేయబడింది, మాంసం మరియు రక్తంతో అలంకరించబడింది; అందులో అహంకారం మరియు మోసం, క్షయం మరియు మరణం దాగి ఉన్నాయి.",
  "151": "రాజుల అద్భుతమైన రథాలు అరిగిపోతాయి; శరీరం కూడా వృద్ధాప్యానికి వస్తుంది; కాని మంచివారి పుణ్యం ఎన్నటికీ అరిగిపోదు. ఈ విధంగా సాధువులు ఒకరికొకరు బోధించుకుంటారు.",
  "152": "తక్కువ నేర్చుకొన్న మనిషి ఎద్దులాగా వృద్ధుడవుతాడు; అతని మాంసం పెరుగుతుంది, కానీ అతని జ్ఞానం పెరగదు.",
  "153": "చాలా జీవితాలు నన్ను పట్టుకున్నాయి, ఈ ఇంద్రియాల జైళ్లను సృష్టించిన వ్యక్తిని కోరుతూ, దుఃఖంతో నిండి నిరంతరం కష్టపడ్డాను.",
  "154": "కానీ ఇప్పుడు, ఈ దేహాన్ని నిర్మించేవాడైన నిన్ను నేను చూసాను! నువ్వు ఈ నొప్పి గోడలను మళ్లీ నిర్మించలేవు, మోసపూరిత పైకప్పులు, నిర్మాణాలను సృష్టించలేవు. నీ ఇల్లు విరిగిపోయింది, నీ మాయ ఇకపై నన్ను తాకలేదు. నేను ముక్తిని పొందేందుకు ఇక్కడి నుండి క్షేమంగా వెళుతున్నాను.",
  "155": "పవిత్రమైన మనస్సుతో క్రమశిక్షణతో కూడిన జీవితాన్ని గడప కుండా, చిన్న వయస్సులో ఆత్మ సంపదను సేకరించని పురుషులు, చేపలు లేని సరస్సులో ముసలి కొంగలవలె ఆరిపోతారు.",
  "156": "పవిత్రమైన మనస్సుతో క్రమశిక్షణతో కూడిన జీవితాన్ని గడప కుండా, చిన్న వయస్సులో ఆత్మ సంపదను సేకరించని పురుషులు, అరిగిపోయిన, పనికిమాలిన విల్లు లాగా పడుండి, గతం గురించి ఆలోచిస్తూ నిట్టూరుస్తూ ఉంటారు.",
  "chap12": "స్వీయం",
  "157": "ఒక వ్యక్తి తనను తాను ప్రేమించినట్లయితే, అతడు శ్రద్ధగా తనను తాను చూసుకోవాలి. తెలివైన వ్యక్తి రాత్రి మూడు భాగాలలో ఒకదానిలో అప్రమత్తంగా ఉండాలి.",
  "158": "ప్రతి వ్యక్తి ఇతరులకు మార్గనిర్దేశం చేయడానికి ప్రయత్నించే ముందు వారి స్వంత మార్గాన్ని కనుగొనాలి. ఈ విధంగా, తెలివైన వ్యక్తులు బాధ పడరు.",
  "159": "ఇతరులకు బోధించే ముందు, ప్రతి వ్యక్తి తనను తాను తీర్చిదిద్దుకోనివ్వండి. స్వీయ నియంత్రణలో నైపుణ్యం సాధించడం ద్వారా, వారు ఇతరులకు మార్గనిర్దేశం చేయగలరు. తనను తాను నియంత్రించుకోవడం ఎంతో కష్టమైన పని.",
  "160": "తానే తనకు దేవుడు. తనకు మించిన దేవుడు లేడు. ఒక వ్యక్తి తన స్వంత మనస్సును స్వాధీనం చేసుకున్నప్పుడు, గొప్ప దేవుడిని కనుగొనడం అరుదు.",
  "161": "ఒక వజ్రం, గట్టి విలువైన రాయిని పగులగొట్టినట్లుగా, తాను చేసిన చెడు, తన ద్వారానే పుట్టి, తన ద్వారా ఉత్పత్తి చెంది, మూర్ఖుడిని నలిపివేస్తుంది.",
  "162": "ఒక 'మాలువ' లత 'సాల' చెట్టును చుట్టినట్లు, చెడు ధోరణులు ఉన్నవాడు, తన శత్రువులు కోరుకునే స్థితిలోకి జారిపోతారు.",
  "163": "చెడు చేయడం సులభం; హాని కలిగించే పనులు ఒకనికి సులభంగా వస్తాయి. ప్రయోజనకరమైన, మంచి పనులు చేయడం చాలా కష్టం.",
  "164": "మూర్ఖుడు పవిత్రులు, శ్రేష్ఠులు మరియు సద్గురువుల బోధనలను దూషిస్తాడు; అతను తన స్వంత నాశనానికి దారితీసే తప్పుడు సిద్ధాంతాలను అనుసరిస్తాడు.",
  "165": "చెడు తనంతట తానే జరుగుతుంది; స్వతహాగా మాత్రమే ఒకడు అపవిత్రుడు అవుతాడు. స్వతహాగా మాత్రమే చెడు వదిలివేయబడుతుంది; తనని తాను మాత్రమే శుద్ధి చేసుకోగలడు. స్వచ్ఛత మరియు అస్వఛ్ఛత ఒకరి సొంతం. ఏ మనిషి మరొకరిని శుద్ధి చేయలేడు.",
  "166": "ఎంత ముఖ్యమైనదైనా ఇతరుల కోసం మీ స్వంత మంచి పనులను విస్మరించవద్దు. మీరు మీ స్వంత మార్గాన్ని తెలుసుకున్న తర్వాత, దానికి మీరు అంకితం అయిపోవాలి.",
  "chap13": "ప్రపంచం",
  "167": "చెడు యొక్క మార్గాన్ని అనుసరించవద్దు. నిర్లక్ష్యంగా జీవించవద్దు. తప్పుడు సిద్ధాంతాన్ని అనుసరించవద్దు. ప్రాపంచిక మార్గాలతో స్నేహం చేయవద్దు.",
  "168": "జాగ్రత్తగా ఉండండి. అజాగ్రత్తగా ఉండకండి. ధర్మం యొక్క చట్టాన్ని అనుసరించండి. సత్పురుషులు ఇహలోకంలోనూ, పరలోకంలోనూ సుఖంగా జీవిస్తారు.",
  "169": "ధర్మం యొక్క చట్టాన్ని అనుసరించండి. పాపం యొక్క చట్టాన్ని అనుసరించవద్దు. సత్పురుషులు ఇహలోకంలోనూ, పరలోకంలోనూ సుఖంగా జీవిస్తారు.",
  "170": "ప్రపంచాన్ని బుడగలా చూడండి. దాన్ని ఎండమావి అని గ్రహించండి. ప్రపంచాన్ని ఇలా చూసేవాడిని మరణం చూడదు.",
  "171": "ఈ ప్రపంచాన్ని చూడండి, ఇది రంగులతో, నగలతో, అలంకరించబడిన రథం వంటిది. బుద్ధిహీనులు ఇందులో మునిగిపోతారు; వివేచనాపరులు దాన్ని చూసి మురిసిపోరు.",
  "172": "ఒకప్పుడు అజాగ్రత్తగా ఉండి, ఇప్పుడు సంయమనంతో ప్రతిబింబించేవాడు మేఘం నుండి విముక్తి పొందిన చంద్రుని వంటివాడు; అతను ప్రపంచాన్ని ప్రకాశవంతం చేస్తాడు.",
  "173": "తన సత్కార్యాల ద్వారా తన చెడు చర్యలను మార్చుకునేవాడు మేఘం నుండి విముక్తి పొందిన చంద్రుని వంటివాడు.",
  "174": "ఈ ప్రపంచం అంధకారంలో ఉంది. ఇక్కడ కొంతమంది మాత్రమే చూడగలరు. కొన్ని పక్షులు మాత్రమే ఈ వల నుండి తప్పించుకుంటాయి. కొందరు మాత్రమే పరలోకపు వెలుగులోకి తప్పించుకుంటారు.",
  "175": "హంసలు తమ అతీంద్రియ శక్తుల కారణంగా సూర్యుని మార్గాన్ని తీసుకుంటాయి. అలాగే తెలివిగల్ల వారు కూడా మారా ని జయించిన తరువాత ఈ లోకాన్ని విడిచి వెళ్తారు.",
  "176": "మంచి చట్టాన్ని ఉల్లంఘించేవాడు, తప్పుగా మాట్లాడేవాడు, మరొక ప్రపంచం ఉనికిని వెక్కిరించేవాడు, చేయలేని చెడు లేదు.",
  "177": "మూర్ఖులకు స్వర్గపు అనుగ్రహం తెలియదు. మూర్ఖులు ఔదార్యాన్ని మెచ్చుకోరు. కానీ జ్ఞానులు, దానధర్మాలలో సంతోషిస్తూ, ఆ ప్రపంచాన్ని ఆనందిస్తారు.",
  "178": "సోటపట్టి ధారలోకి ప్రవేశించడం ప్రపంచ సార్వభౌమత్వం కంటే ఉత్తమం, స్వర్గానికి వెళ్లడం కంటే ఉత్తమం, అనేక లోకాల ప్రభువు అవడం కంటే ఉత్తమం.",
  "chap14": "బుద్ధుడు",
  "179": "జ్ఞానోదయం పొందిన వ్యక్తిని మీరు ఎలా ప్రలోభపెట్టగలరు? వారు ఎటువంటి ప్రాపంచిక ప్రలోభాలకు అతీతులు కారు కాబట్టి ఇది అసాధ్యం. వారి విజయాన్ని మామూలు జనులు ముట్టుకోలేరు. వారి విజయం అనివార్యం, ఈ ప్రపంచంలో ఎవరూ ఆ విజయాన్ని ప్రభావితం చేయలేరు. వారి దృష్టి అపారమైనది.",
  "180": "జ్ఞానోదయం పొందిన వ్యక్తిని మీరు ఎలా ఆకర్షించగలరు? ఆ వ్యక్తి సాధారణ ఆలోచనా విధానానికి అతీతుడు కాబట్టి ఇది కష్టం. ఏ కోరికల వలయైనా ఆయనను పట్టుకోలేవు. ఏ తృష్ణ అతనిని చిక్కుకోలేదు. అతను అపారమైన దృష్టిని కలిగియున్నాడు.",
  "181": "దేవతలు కూడా గొప్ప ఆలోచనాపరులైన, శాంతియుతులైన, స్థిరంగా మరియు ప్రశాంతంగా ఉండే జ్ఞానోదయం పొందిన జ్ఞానులను అనుకరించాలని కోరుకుంటారు.",
  "182": "మనిషిగా పుట్టడం కష్టం. మనిషి జీవితాన్ని గడపడం కష్టం. మనిషి జీవితం దొరికినతరువాత ధర్మం చెవిన పడటం కష్టం. జ్ఞానోదయం పొందడం కష్టం.",
  "183": "అన్ని చెడులను విడిచిపెట్టండి. మంచిలో మిమ్మల్ని మీరు సంస్కరించుకోండి. మనస్సును శుభ్రపరచుకొండి. బుద్ధులు ఇవే నేర్పిస్తారు.",
  "184": "ఓర్పు, సహనం అత్యున్నత తపస్సు; మోక్షం అత్యున్నత స్థితి - బుద్ధులు బోధించేది ఇదే. మరొకరిని అణచివేసేవాడు, మరొకరికి హాని చేసేవాడు సన్యాసి కాదు.",
  "185": "దూషించవద్దు, హాని చేయవద్దు, చట్ట ప్రకారం మిమ్మల్ని మీరు క్రమశిక్షణలో ఉంచుకోండి, ఆహారంలో మితంగా ఉండండి, ఏకాంతంగా నివసించండి, ఉన్నతమైన ఆలోచనలకు అంకితం కండి - ఇదే బుద్ధుల బోధ.",
  "186": "కామం ఎప్పటికి చల్లబడదు. స్వర్ణవర్షం వల్ల కూడా కోరికలు తీరవు. మోహము యొక్క భోగము స్వల్పకాలము, మరియు అది నొప్పి కి దారి తీస్తుంది అని తెలిసినవాడు జ్ఞాని.",
  "187": "ఆకాశ భోగాలలో కూడా అతనికి ఆనందమే లేదు. పరమాత్ముని శిష్యుడు తృష్ణ నాశనం చేయడంలో ఆనందం పొందుతాడు.",
  "188": "భయంతో ముందుకు సాగే పురుషులు పర్వతాలపై, అడవుల్లో, చెట్ల కింద లేదా పుణ్యక్షేత్రాల వద్ద ఆశ్రయం పొందుతారు.",
  "189": "అటువంటి ఆశ్రయం సురక్షితమైనది కాదు, అటువంటి శరణు ఉత్తమమైనది కాదు. అలాంటి ఆశ్రయం మనిషిని బాధ నుండి విముక్తి చేయదు.",
  "190": "భద్రతా, మార్గదర్శకత్వం కోసం ఎవరైనా జ్ఞానోదయం, ధర్మం మరియు క్రమాన్ని ఆశ్రయించినప్పుడు, వారు నాలుగు ముఖ్యమైన సత్యాలను అర్థం చేసుకోగలరు:",
  "191": "బాధ, బాధలకు గల కారణాలు, బాధల అంతం మరియు బాధ నుండి విముక్తికి దారితీసే 'నోబుల్ ఎయిట్ ఫోల్డ్' మార్గం.",
  "192": "నొప్పి నుండి ఉపశమనం పొందేందుకు ఇది సురక్షితమైన మరియు ఉత్తమమైన మార్గం.",
  "193": "ఉన్నతమైన వ్యక్తి అరుదుగా కనిపిస్తాడు. అతను అంత సులువుగా పుట్టడు. జ్ఞానవంతుడు, గొప్పవాడు ఎక్కడ జన్మిస్తాడో, ఆ ఇల్లు వర్ధిల్లుతుంది.",
  "194": "బుద్ధుని జన్మ ధన్యమైనది; ధర్మశాస్త్ర బోధ ధన్యమైనది; చట్టం కి కట్టుబడి సామరస్యంగా జీవించినప్పుడు అది దీవెన తో సమానం. స్వీయ క్రమశిక్షణ మరియు సరళతను పాటిస్తే అది దీవెన తో సమానం.",
  "195": "జ్ఞానోదయులైనా, వారి శిష్యులైనా - దుష్ప్రవర్తనను అధిగమించి, ప్రవాహాన్ని దాటిన వారు",
  "196": "నిర్భయ మరియు శాంతియుతంగా ఉండే వారిని అనుసరించే వారి జ్ఞానాన్ని కొలవలేము.",
  "chap15": "సంతోషం",
  "197": "మనం అందరం, ద్వేషం లేకుండా సంతోషంగా జీవిద్దాం; ద్వేషించే మనుషుల మధ్య; ద్వేషించే పురుషుల మధ్య ద్వేషం లేకుండా జీవిద్దాం.",
  "198": "కాంక్ష అనే వ్యాధి నుండి విముక్తి పొంది, ఆ వ్యాధితో బాధపడేవారి మనుషుల మధ్య, ఆ వ్యాధి సోకించనీయకుండా, సంతోషంగా జీవిద్దాం.",
  "199": "ఆందోళన నుండి విముక్తి పొందుదాం, నిరంతరం ఆందోళన చెందే వారి మధ్య సంతోషంగా, ఆందోళన లేకుండా జీవిద్దాం.",
  "200": "మనము, ఎటువంటి ప్రాపంచిక ఆస్తులు కలిగి లేకపోయినా సంతోషంగా జీవిద్దాం. ఆనందంతో పోషించబడి, ప్రకాశిస్తూ మనం జీవిద్దాం.",
  "201": "విజయం ద్వేషాన్ని పెంచుతుంది; ఓడిపోయిన వారు బాధలో నివసిస్తారు; కానీ ప్రశాంతమైన మనిషి, ఓటమీ విజయాలను రెండింటినీ పట్టించుకోకుండా సంతోషంగా జీవిస్తాడు.",
  "202": "కామం వంటి అగ్ని లేదు; ద్వేషం వంటి అనారోగ్యం లేదు; బ్రతకడం లాంటి దుఃఖం లేదు; మోక్షం కంటే గొప్ప శాంతి లేదు.",
  "203": "ఆకలి అనేది రోగాలలో అతి భయంకరమైనది, బ్రతకడం అన్ని బాధలలో కెల్లా అతి దారుణమైనది. ఇది నిజంగా, పూర్తిగా అర్ధం చేసుకున్న వ్యక్తికీ, మోక్షమే పరమానందం.",
  "204": "ఆరోగ్యం అన్ని బహుమతులలో కెల్లా గొప్పది; సంతృప్తి అన్ని సంపదలలోకెల్లా గొప్పది; నమ్మకం అన్నిటికన్నా శ్రేష్ఠమైన సంబంధం; మోక్షము అత్యున్నతమైన ఆనందం.",
  "205": "ఒంటరితనంలోని మాధుర్యాన్ని, ప్రశాంతత యొక్క రుచిని అనుభవించినవాడు, పాపం నుండి విముక్తుడై, నిర్భయుడు అవుతాడు. మంచి ధర్మం యొక్క అమృతాన్ని అనుభవిస్తాడు.",
  "206": "గొప్పవారి సాంగత్యం ప్రయోజనకరం; వారితో జీవించడం నిరంతర ఆనందం. మూర్ఖుల దృష్టి నుండి తప్పించుకున్న మనిషి సంతోషిస్తాడు.",
  "207": "మూర్ఖులతో సహవాసం చేసేవాడు దుఃఖాన్ని అనుభవిస్తాడు. మూర్ఖుల సహవాసం శత్రువులతో సాంగత్యం వంటిది. జ్ఞానుల సహవాసం నిజమైన బంధుమిత్రులను కలవడం లాంటిది, ఆనందాన్ని కలిగిస్తుంది.",
  "208": "చుక్కల్లో చంద్రుడు తన మార్గాన్ని అనుసరిస్తున్నట్లుగా, మనిషి, జ్ఞానులని, మంచి నిర్ణయాలు తీసుకునే వాళ్ళని, కర్తవ్యం తో నడుచుకునే వాళ్ళని, కీర్తి ఉన్న వారిని, శ్రేష్ఠమైన గుణం ఉన్న వారిని అనుసరించాలి. అలాగే ఆ గుణాలన్నీ పాటించాలి.",
  "chap16": "ప్రేమ",
  "209": "పరధ్యానానికి తనను తాను సమర్పించుకునేవాడు, స్వంత సంక్షేమాన్ని వదులుకుంటాడు; భోగభాగ్యాలను వెంబడిస్తూ, ధ్యానంలో శ్రమించే వ్యక్తిని చూసి అసూయపడతాడు.",
  "210": "ఆహ్లాదకరమైన వాటిని లేదా అసహ్యకరమైన వాటిని అంటిపెట్టుకుని ఉండకండి. ఆహ్లాదకరమైనవి దక్కకపోవడం, అసహ్యకరమైనవి దక్కడం - రెండూ బాధాకరమైనవే.",
  "211": "కాబట్టి దేనికీ ఆకర్షితులవకండి, ఎందుకంటే ప్రియమైన వస్తువును కోల్పోవడం బాధాకరం. దేనిని ఇష్టపడని, ద్వేషించని వాడికి సంకెళ్లు ఉండవు.",
  "212": "అనుబంధం నుండి దుఃఖం పుడుతుంది, అనుబంధం నుండి భయం పుడుతుంది. బంధం లేనివాడికి దుఃఖం ఉండదు. అలాంటప్పుడు భయం ఎక్కడ నుండి వస్తుంది?",
  "213": "అనురాగం నుండి శోకం పుడుతుంది, అనురాగం నుండి భయం పుడుతుంది. అనురాగం లేని వాడికి దుఃఖం ఉండదు. అప్పుడు భయం ఎక్కడ నుండి వస్తుంది?",
  "214": "భోగము నుండి దుఃఖము పుడుతుంది; భోగము నుండి భయం పుడుతుంది. భోగము నుండి విముక్తుడైన వానికి దుఃఖము ఉండదు. అలాంటప్పుడు భయం ఎక్కడ నుండి వస్తుంది?",
  "215": "కోరిక నుండి దుఃఖం పుడుతుంది; కోరిక నుండి భయం పుడుతుంది. కోరిక నుండి విముక్తుడైన వానికి దుఃఖం ఉండదు. అలాంటప్పుడు భయం ఎక్కడ నుండి వస్తుంది?",
  "216": "తృష్ణ నుండి దుఃఖం పుడుతుంది; తృష్ణ నుండి భయం పుడుతుంది. తృష్ణ నుండి విముక్తుడైన వానికి దుఃఖం ఉండదు. అలాంటప్పుడు భయం ఎక్కడ నుండి వస్తుంది?",
  "217": "సద్గుణం మరియు అంతర్దృష్టి రెండూ ఉన్నవాడు, చట్టంలో స్థిరపడినవాడు, సత్యవంతుడు మరియు తన స్వంత కర్మను నెరవేర్చుకునే వ్యక్తిని, ప్రజలందరూ ప్రేమిస్తారు.",
  "218": "వర్ణించలేని దానిగురించి, పెద్ద కోరికలు ఉన్నవాడు, ఆ కోరిక మనస్సులో వ్యాపించి ఉన్న వాడు, చిన్న చిన్న కోరికలపై దృష్టి పెట్టని వాడు, నది ఒక వైపు పారుతుంటే, దాని వ్యతిరేక దిశలో ఈదుతున్నాడు.",
  "219": "చాలా దూరం వెళ్లిన వ్యక్తి, క్షేమంగా తిరిగి వచ్చినప్పుడు, బంధువులు, స్నేహితులు మరియు శ్రేయోభిలాషుల నుండి స్వాగతాన్ని ఎలా అయితే అందుకుంటాడో;",
  "220": "ప్రాపంచిక స్థితిని విడిచిపెట్టి ఉన్నత స్థితిని పొందిన వ్యక్తిని, అతని మంచి పనులు, పుణ్య కార్యాలు స్వాగతిస్తాయి; అతను చేసిన మంచి పనులే అతని బంధువులు.",
  "chap17": "క్రోధం",
  "221": "మనిషి కోపాన్ని విడిచిపెట్టాలి; అహంకారాన్ని పారద్రోలాలి; అతడు అన్ని సంకెళ్లను బద్దలు కొట్టాలి. పేరు మరియు రూపాన్ని అంటిపెట్టుకుని ఉండకుండా, దేనినీ 'తనది' అని పిలవని వ్యక్తికి ఎటువంటి బాధలు ఉండవు.",
  "222": "ఏ వ్యక్తి అయితే అదుపు తప్పిన రథం లాంటి తన కోపాన్ని అదుపు చేసుకుంటాడో, వాడు అసలైన రథసారథి, మిగితా వారు పగ్గాలు పట్టుకున్న కూడా రథసారథి అనిపించుకోరు.",
  "223": "మనిషిని కోపాన్ని సౌమ్యతతో జయించనివ్వండి; మంచి ద్వారా చెడును జయించనివ్వండి; అతను ఉదారత ద్వారా పిసినారితనం ని అధిగమించనివ్వండి; అబద్ధాలు చెప్పేవాడిని సత్యముతో జయించనివ్వండి.",
  "224": "నిజం మాట్లాడండి; కోపానికి లొంగకండి; అడిగితే, కొంచెం అయినా సరే, సహాయం చేయండి. ఈ మూడు మెట్ల ద్వారా మనిషి దేవతల సన్నిధికి చేరుకుంటాడు.",
  "225": "ఎవరికీ హాని కలిగించని, తమ శరీరాన్ని ఎల్లప్పుడూ నియంత్రన లో పెట్టుకునే ఋషులు, మార్పులేని స్థితిని పొందుతారు; అక్కడ దుఃఖం ఉండదు.",
  "226": "మనిషి జాగరూకతతో, పగలు మరియు రాత్రులు శ్రద్ధగా ఉండి, మోక్షం కోసం ప్రయత్నించినప్పుడు అన్ని కలుషితాలు మాయమవుతాయి.",
  "227": "ఇది ఒక పాత సామెత, 'మౌనంగా కూర్చున్నవాడిని నిందిస్తారు, ఎక్కువ మాట్లాడేవాడిని నిందిస్తారు, మితంగా మాట్లాడేవాడిని నిందిస్తారు' ప్రపంచంలో నిందించబడని వారు ఎవరూ ఉండరు.",
  "228": "పూర్తిగా ప్రశంసించబడిన లేదా పూర్తిగా ఖండించబడిన వారు చరిత్రలో ఎవరూ లేరు, ఉండరు కూడా.",
  "229": "మెరుగైన వారి నుండి నిరంతరం ప్రశంసలు పొందే వ్యక్తి నిజంగా గొప్పవాడు. వారు తెలివైనవారు, జ్ఞానం, మంచితనం రెండింటినీ కలిగి ఉంటారు.",
  "230": "అలాంటి వ్యక్తిని విమర్శించే ధైర్యం ఎవరికి ఉంటుంది? వాళ్ళు జంబూ నదిలో దొరికిన బంగారు నాణెం లాంటి వారు. దేవతలు మరియు బ్రహ్మ కూడా వారిని ప్రశంసిస్తారు.",
  "231": "మనిషి తన శారీరక చికాకులను గమనించుకోవాలి. పాపపు చర్యలను విడిచిపెట్టాలి, బదులుగా శరీరం, మనస్సులో పుణ్యాలను స్థాపించడంపై దృష్టి పెట్టాలి.",
  "232": "మనిషి తన మాటలపై ద్రుష్టి పెట్టాలి. అతను తన ప్రసంగాన్ని నియంత్రించుకోవాలి. వాక్కు పాపములను త్యజించి తన వాక్కుతో పుణ్యమును ఆచరించాలి.",
  "233": "మనిషి మనస్సు ని అదుపు లో ఉంచాలి. మనస్సుని పట్టులోకి తీసుకు రావాలి. మనస్సు యొక్క పాపాలను విడిచిపెట్టి, తన మనస్సుతో పుణ్యాన్ని ఆచరించాలి.",
  "234": "జ్ఞానులు బాగా నియంత్రణ లో ఉంటారు; వారికి శరీరం, నాలుక మరియు మనస్సుపై పట్టు ఉంటుంది.",
  "chap18": "మలం",
  "235": "నువ్వు ఇప్పుడు ఎండిపోయిన ఆకు లాంటివాడివి. యమ దూతలు నిన్ను సమీపిస్తున్నారు. ఈ లోకాన్ని విడిచిపెట్టే దశలో ఉన్నావు. ప్రయాణానికి కావలిసిన ఎటువంటి సరుకు నీ వద్ద లేవు!",
  "236": "జ్ఞానం కలిగి ఉండండి. మీ కోసం ఒక ద్వీపాన్ని తయారు చేసుకోండి. త్వరగా కష్టపడండి. మరకలు తొలగిపోయి పాపరహితమైన మీరు స్వర్గానికి సిద్ధంగా ఉంటారు, ఎన్నుకోబడిన ప్రపంచానికి సిద్ధంగా ఉంటారు.",
  "237": "మీ జీవితం ఇప్పుడు ముగింపు దశకు చేరుకుంది. మృత్యువు రాజు యముడి వద్దకు సమీపిస్తున్నావు. దారిలో విశ్రాంతి గృహం లేదు. మీరు ప్రయాణానికి ఎటువంటి ఏర్పాటు చేసుకోలేదు.",
  "238": "జ్ఞానం కలిగి ఉండండి. మీ కోసం ఒక ద్వీపాన్ని తయారు చేసుకోండి. త్వరగా కష్టపడండి. మరకల నుండి ప్రక్షాళన చేయబడి, పాపము చేయని మీరు జన్మ మరణాలకు తిరిగి రారు.",
  "239": "ఒక కమ్మరి వెండిలోని మలినాలను తొలగించినట్లుగా, జ్ఞానవంతుడు తన మలినాలను ఒక్కొక్కటిగా, కొద్దికొద్దిగా, రోజురోజుకు తొలగించుకుంటాడు.",
  "240": "ఇనుము నుండి పుట్టుకొచ్చిన తుప్పు దానినే పట్టి తింటుంది, పాపం చేసే మనిషి కూడా అంతే. అతని స్వంత పనులే పాపిని చెడు ముగింపుకు తీసుకువస్తాయి.",
  "241": "పునరావృతం చేయకపోవడం మన ప్రార్థనలను కలుషితం చేస్తుంది. ఇంటికి మరమ్మతులు చేయకాపోతే ఇల్లు కూలిపోతుంది. బద్ధకం మన శరీరాన్ని కలుషితం చేస్తుంది. అజాగ్రత్త కాపలాదారుని కలుషితం చేస్తుంది.",
  "242": "అపవిత్రత స్త్రీని కలుషితం చేస్తుంది. నిస్సహాయత ఒక లబ్ధిదారుని కళంకం చేస్తుంది. చెడు పనులు మనల్ని ఇహలోకంలోనూ, పరలోకంలోనూ కలుషితం చేస్తాయి.",
  "243": "కానీ అన్ని కలుషితాల కంటే అధ్వాన్నమైన కలుషితం ఉంది- అజ్ఞానం. ఓ భిక్షువులారా, ఆ మలినాన్ని తొలగించి, నిర్మలంగా అవ్వండి.",
  "244": "సిగ్గులేనివాడు, కాకిలాగా ధైర్యంగా ఉండేవాడు, దుర్మార్గుడు, అపవాది, అజ్ఞాని మరియు అవినీతిపరుడు సులభంగా జీవిస్తాడు.",
  "245": "నిరాడంబరంగా, ఎల్లప్పుడూ స్వచ్ఛమైన వాటి కోసం వెతుకుతున్న, అనవసరమైన వాటి పై ఆసక్తి లేని, ఎవరి గురించి చెడుగా అనుకోని, పవిత్రమైన అంతర్దృష్టి ఉన్న వ్యక్తి జీవించడం కష్టం.",
  "246": "జీవితాన్ని నాశనం చేసేవాడు, అసత్యం మాట్లాడేవాడు, ఈ ప్రపంచంలో తనకు ఇవ్వనిది తీసుకునేవాడు, మరొకరి భార్యతో సహవాసం చేసేవాడు,",
  "247": "మత్తు పానీయాలకు బానిస అయినవాడు తన స్వంత జీవితానికి గొప్ప హాని కలిగించుకుంటున్నాడు.",
  "248": "మిత్రమా, చెడు పనులను నియంత్రించడం, నివారించడం సులభం కాదని అర్థం చేసుకో. మీ కోరికలు, మీ తప్పుడు చర్యలు మిమ్మల్ని ఎక్కువ కాలం బాధపడేలా చేయవద్దు.",
  "249": "పురుషులు వారి విశ్వాసం ప్రకారం లేదా వారి సుఖం ప్రకారం ఇస్తారు. అందువల్ల, ఇతరులకు ఇచ్చే ఆహారం లేదా పానీయాల గురించి చింతించేవాడు పగలు రాత్రులు ప్రశాంతత పొందడు.",
  "250": "కానీ ఎవరిలో ఆ భావన నాశనం చేయబడిందో, మూలాల నుంచి లాగేయబడిందో, అతను పగలు మరియు రాత్రి మనశ్శాంతిని అనుభవిస్తాడు.",
  "251": "మక్కువ వంటి అగ్ని లేదు; ద్వేషం లాంటి ఉరితాడు లేదు; మాయ వంటి వల లేదు; కోరిక వంటి ప్రవాహం లేదు.",
  "252": "ఇతరుల తప్పులను చూడడం సులభం; మన సొంత తప్పులని చూడడం కష్టం. ఇతరుల లోపాలను త్వరగా ఎత్తి చూపుతాము, కాని మోసగాడు ఆటలో తన ఓటమిని దాచినట్లుగా మన స్వంత లోపాలను దాచిపెడతాము.",
  "253": "నిరంతరం ఇతరుల లోపాలను వెతుక్కుంటూ వారిని విమర్శించే వ్యక్తి తన బలహీనతలను మాత్రమే పెంచుకుంటాడు. ఆ బలహీనతలను ఆ వ్యక్తి అధిగమించడం చాలా కష్టం.",
  "254": "ఆకాశంలో మార్గం లేదు; సంఘం బయట నిజమైన సన్యాసి లేడు; మానవుడు ప్రాపంచికతలో ఆనందిస్తాడు; బుద్ధులు ప్రాపంచికత నుండి విముక్తులు.",
  "255": "ఆకాశంలో మార్గం లేదు; సంఘ బయట నిజమైన సన్యాసి లేడు; అసాధారణ ప్రపంచంలో ఏదీ మనుగడలో లేదు; కానీ బుద్ధులు ఎప్పుడూ ఒకేలా ఉంటారు.",
  "chap19": "ధర్మంతో నిలబడే మనిషి",
  "256": "తన పని కోసం బలాన్ని ఉపయోగించడం లేదా ఏకపక్షంగా వ్యవహరించినవాడు నీతిమంతుడు కాడు. మంచి చేడుల మధ్య తేడాను గుర్తించిన్నవాడు నిజమైన జ్ఞానీ.",
  "257": "శక్తి లేదా హింస ద్వారా కాకుండా ఇతరులను న్యాయంగా, సమానంగా నడిపించే వాడు జ్ఞాని. ఈ వ్యక్తి ధర్మం యొక్క రక్షకుడు.",
  "258": "మనిషి ఎక్కువగా మాట్లాడటం వల్ల పండితుడు అనిపించుకోడు. ప్రశాంతంగా, ద్వేషం, భయం లేనివాడే నిజమైన పండితుడు.",
  "259": "ఎక్కువ మాట్లాడినంత మాత్రాన మనిషి ధర్మశాస్త్రానికి మూలస్తంభం కాడు. ధర్మశాస్త్రాన్ని గురించి అంతగా వినకపోయినా, వివేచన ఉన్నవాడు, ధర్మశాస్త్రాన్ని ఎల్లప్పుడూ పరిగణించేవాడు ధర్మశాస్త్రానికి మూలస్తంభం, అతడు ధర్మశాస్త్రంలో స్థిరపడతాడు.",
  "260": "జుట్టు నెరిసినంత మాత్రాన మనిషి పెద్దవాడు అయిపోడు. అతని వయస్సు బాగా పండింది, అతనన్ని 'వ్యర్ధ-వృధుడు' అని పిలవాలి.",
  "261": "సత్యం, ధర్మం, అహింస, సంయమనం మరియు నియంత్రణలో నివసించే వ్యక్తి, మలినాలనుండి విముక్తుడు, జ్ఞానవంతుడు అయిన మనిషిని పెద్దాయన అని పిలవచ్చు.",
  "262": "మనిషి అసూయతో, అత్యాశతో, దుర్మార్గంగా ఉన్నప్పుడు, కేవలం మాటలతో, ఛాయ అందం వల్ల సాధువు అనిపించుకోడు.",
  "263": "ఎవరిలోనైతే ఈ మూడూ నశించబడి, మూలాధారంతో తొలగించబడి, అపరాధం లేకుండా ఉండి, జ్ఞానవంతుడు అయిన వాడిని సాధువు అని అంటారు.",
  "264": "క్రమశిక్షణ లేకుండా అబద్ధం చెప్పే వ్యక్తి తల గొరిగించుకుంటే సన్యాసి అయిపోడు. కోరికలు, దురాశలతో నిండినవాడు సన్యాసి ఎలా అవుతాడు?",
  "265": "పాప ధోరణులను అధిగమించేవాడు, అవి చిన్నవి అయినా, పెద్దవి అయినా, అతన్ని సన్యాసి అంటారు. అతను అన్ని పాపాలను విడిచిపెట్టాడు.",
  "266": "భిక్షాపాత్రను మోసినంత మాత్రాన, బాహ్యంగా చట్టాలను అనుసరించిన మాత్రాన భిక్షువు అనిపించుకోడు.",
  "267": "అయితే మంచి చెడులకు అతీతంగా ఉన్నవాడు, పవిత్రుడు, అవగాహనతో లోకంలో తనను తాను పోషించుకునేవాడు, అతను నిజంగా భిక్కు అని పిలువబడతాడు.",
  "268": "నిశ్శబ్దం మాత్రమే ఒకరిని మునిగా మార్చదు; వారు అప్పటికీ మూర్ఖులు కావచ్చు. అవగాహన అనే తూకంపై మంచీ చెడులను చూస్తూ, మంచిని అంగీకరించి, చెడును తిరస్కరింస్చేవాడు తెలివైనవాడు; ఆ కారణం చేత అతను తెలివైనవాడు.",
  "269": "ఎవరైతే మౌనంగా అంతరంగాన్ని, బాహ్యాన్ని ప్రతిబింబిస్తారో, అతడ్ని ముని అని అంటారు.",
  "270": "జీవులకు హాని చేస్తే మనిషి గొప్పవాడు అనిపించుకోడు. అహింసను ఆచరించడంలోనే నిజమైన గొప్పతనం ఉంటుంది.",
  "271": "కేవలం నైతిక సూత్రాల క్రమశిక్షణ వల్లో, కేవలం తీర్మానాలు మరియు ప్రమాణాల వల్లనో; కేవలం అధ్యయనం వల్లనో, ధ్యానంలో లేదా ఏకాంతం వల్లనో, నేను బానిసత్వం నుండి బయటపడి ఆనందం వైపు వెళ్ళలేను. ఇది లోకవాసులచే సాధించబడదు.",
  "272": "ఓ భిక్షూ, కోరికలు నశించనంత కాలం ఆత్మవిశ్వాసంతో మోసపోకు.",
  "chap20": "దారి",
  "273": "మార్గాలలో ఉత్తమమైనది అష్టాంగిక; సత్యాలలో ఉత్తమమైనవి నాలుగు గొప్ప సత్యాలు; మానసిక స్థితుల్లో ఉత్తమమైనది నిర్లిప్తత (విరాగ్య); పురుషులలో శ్రేష్ఠుడు సాధువు.",
  "274": "ఇదే దారి. స్వచ్ఛమైన దృష్టికి మరే ఇతర దారి లేదు. మీరు ఈ మార్గం లోకి అడుగు పెట్టండి. ఆ విధంగా మీరు మారాను ఎదురుకోవచ్చు.",
  "275": "ఈ మార్గంలో నడవడం ద్వారా, మీరు మీ బాధలను అంతం చేసుకోవచ్చు. మాంసం లోని ముళ్లను ఎలా తొలగించాలో నేర్చుకోగానే నేను మీ అందరికీ చెప్పడం జరిగింది.",
  "276": "మీరే కష్టపడాలి; బుద్ధులందరు మైలురాళ్ళు మాత్రమే. ఎవరైతే మార్గములో ప్రవేశించి, తమను తాము క్రమశిక్షణలో పెట్టుకుంటారో వారు మారా బంధనము నుండి విముక్తులవుతారు.",
  "277": "'అన్ని ప్రాణులు అశాశ్వతమైనవి.' ఇది తెలుసుకున్న మనిషిలో దుఃఖం ఆగిపోతుంది. ఇది స్వచ్ఛత యొక్క మార్గం.",
  "278": "'అన్ని ప్రాణులూ నొప్పితో నిండి ఉన్నాయి.' ఇది తెలుసుకున్న మనిషిలో దుఃఖం ఆగిపోతుంది. ఇది స్వచ్ఛత యొక్క మార్గం.",
  "279": "'అన్ని ప్రాణులూ అసంబద్ధం.' ఇది తెలుసుకున్న మనిషిలో దుఃఖం ఆగిపోతుంది. ఇది స్వచ్ఛత యొక్క మార్గం.",
  "280": "యవ్వనమూ, బలమూ ఉన్నప్పటికీ, సోమరితనంతో లేచి నిలబడలేక, బలహీనమైన సంకల్పం మరియు ఆలోచనతో, సోమరిపోతు జ్ఞాన మార్గాన్ని కనుగొనలేడు.",
  "281": "వాక్కును కాపాడుకుంటూ, మనస్సును నియంత్రించుకుంటూ, శారీరక తప్పులను నివారించడం ద్వారా ఒక వ్యక్తి జ్ఞానులు బోధించిన మార్గాన్ని కనుగొంటాడు.",
  "282": "క్రమశిక్షణతో కూడిన యోగా నుండి జ్ఞానం వస్తుంది, అది చేయకపోతే జ్ఞానం నశిస్తోంది. పురోగతి మరియు క్షీణత అనే రెండు రకాల మార్గాలను గుర్తించి, పురోగతి మార్గాన్ని ఎంచుకోండి.",
  "283": "ఒక్క చెట్టు కాదు, కోరికల అడవి మొత్తాన్ని నరికివేయు; ఆ అడవిలో ప్రమాదం పొంచి ఉంది. చెట్లను నరికి, కోరిక అనే కలుపు మొక్కలను నిర్మూలించి, ఓ భిక్కువులారా, మీరు స్వేచ్ఛను పొందుతారు.",
  "284": "స్త్రీ పట్ల పురుషుని కోరిక ఎంత చిన్నదైనా, అది నశించనంత కాలం అతని మనసు, ఆవు పొదుగుని విడువని దూడ వలె అతుక్కుపోయి ఉంటుంది.",
  "285": "శరదృతువులో రాలిపోయే ఆకుల్లాగా మీ పైన మీకున్న ప్రేమను కత్తిరించండి. అప్పుడు శాంతి మార్గాన్ని, మోక్షాన్ని ఆశ్రయించండి. శాంతిపరుడు దీన్ని చూపించాడు.",
  "286": "'నేను వర్షాకాలాన్ని ఇక్కడ గడుపుతాను, ఎండా కాలంలో అక్కడ, చలికాలంలో ఎక్కడో గడుపుతాను' అని అనుకోవడం అవివేకం. ఈ మనిషి జీవితంలోని అడ్డంకులను పరిగణించడు.",
  "287": "వరదలు నిద్రిస్తున్న గ్రామాన్ని కబళించినట్లే, మృత్యువు ఆస్తులు మరియు కుటుంబంతో నిమగ్నమై ఉన్న వ్యక్తిని తరుముకు పోతుంది. అలాంటి వ్యక్తి మనసు చెదిరిపోతుంది.",
  "288": "మృత్యువు వచ్చినప్పుడు కొడుకులు, తండ్రులు, బంధువులు రక్షించలేరు. ఎవరినుండి ఎలాంటి సహాయం అందదు.",
  "289": "దీన్ని అర్థం చేసుకుని, తెలివైన, మంచి వ్యక్తి వెంటనే మోక్షానికి మార్గం సుగమం చేయడం ప్రారంభించాలి.",
  "chap21": "ఇతరాలు",
  "290": "చిన్న ఆనందాన్ని వదులుకోవడం గొప్ప ఆనందాన్ని కలిగిస్తే, తెలివైన వ్యక్తి చిన్న ఆనందాన్ని విడిచిపెట్టి మెరుగైన ఆనందాన్ని కోరుకుంటాడు.",
  "291": "తన సంతోషం కోరుకుంటూ, తన సంతోషం కోసం ఇతరులకు హాని కలిగించే వ్యక్తి, ద్వేషంలో చిక్కుకు పోతాడు. అలాంటి వ్యక్తి ద్వేషం నుండి విముక్తి పొందడు.",
  "292": "చేయవలసిన పనిని నిర్లక్ష్యం చేసి, చేయకూడని పనిని చేస్తే, నిగ్రహం లేని అజాగ్రత్త పరుడి చెడు ధోరణులు పెరుగుతాయి.",
  "293": "అయితే దేహసంబంధమైన కార్యాలను అవగాహనలో ఉంచుకొని, చేయకూడనిది చేయకుండా, చేయవలసిన పనిని స్థిరంగా చేసేవారిలో దుష్ట ప్రవృత్తి తగ్గిపోయి అంతం అయిపోతాయి.",
  "294": "తల్లిదండ్రులను, క్షత్రియ కులంలోని ఇద్దరు రాజులను, మొత్తం రాజ్యాన్ని చంపినప్పటికీ నిజమైన బ్రాహ్మణుడు క్షేమంగా ఉంటాడు.",
  "295": "తల్లిదండ్రులను, బ్రాహ్మణ కులంలోని ఇద్దరు రాజులను చంపినప్పటికీ, నిజమైన బ్రాహ్మణుడు క్షేమంగా ఉంటాడు.",
  "296": "నిజంగా మేల్కొని ఉన్న గౌతముని శిష్యులు ఎప్పుడూ పగలు రాత్రి బుద్ధుని గురించి ఆలోచిస్తారు.",
  "297": "నిజంగా మేల్కొని ఉన్న గౌతముని శిష్యులు ఎప్పుడూ పగలు రాత్రి, ధర్మం గురించి ఆలోచిస్తారు.",
  "298": "నిజంగా మేల్కొని ఉన్న గౌతముని శిష్యులు ఎప్పుడూ పగలు రాత్రి సంఘం గురించి ఆలోచిస్తారు.",
  "299": "నిజంగా మేల్కొని ఉన్న గౌతముని శిష్యులు ఎల్లప్పుడూ పగలు రాత్రి, శరీరం యొక్క నిజమైన స్వభావం (కాయగత సతి) గురించి ఆలోచిస్తారు.",
  "300": "నిజంగా మేల్కొని ఉన్న గౌతముని శిష్యులు అహింసా - అహింసకు సంబంధించిన ఆనందం గురించి పగలు రాత్రి ఎల్లప్పుడూ ఆలోచిస్తారు.",
  "301": "నిజంగా మేల్కొని ఉన్న గౌతముని శిష్యులు ఎల్లప్పుడూ పగలు రాత్రి, భావన (సృజనాత్మక ధ్యానం) యొక్క ఆనందాల గురించి ఆలోచిస్తారు.",
  "302": "ఏకాంత జీవితం కష్టం, దాని క్రమశిక్షణను ఆస్వాదించడం కష్టం. గృహస్థుని జీవితం కూడా కష్టతరమైనది, ముఖ్యంగా ఇంట్లో. సానుభూతి లేని వారితో జీవించడం బాధాకరమైనది. ఒంటరిగా తిరుగుతూ ఉండటం కూడా కష్టమే. వీలైనంత వరకు పరుల బాధలు తగ్గించడానికి ప్రయత్నించండి.",
  "303": "విశ్వాసం, ధర్మం, కీర్తి మరియు శ్రేయస్సు ఉన్న వ్యక్తి ఎక్కడికి వెళ్లినా గౌరవించబడతాడు.",
  "304": "మంచి వ్యక్తులు దూరం నుండి హిమాలయ శిఖరాల వలె ప్రకాశిస్తారు, దుష్టులు రాత్రి పూట చీకట్లోకి వేసిన బాణాల వలె అదృశ్యమవుతారు.",
  "305": "స్వీయ నియంత్రణ ద్వారా అలసిపోకుండా తమను తాము లొంగదీసుకుని ఒంటరిగా కూర్చోండి, నిద్రపోండి మరియు పని చేయండి. కోరికల అడవి నుండి బయట పడి ఆనందాన్ని పొందుతారు.",
  "chap22": "తప్పు దోవ",
  "306": "జరగని దాన్ని జరిగిందని చెప్పినవాడు నరకానికి వెళ్తాడు. చేసిన పనిని చేయలేదు అని చెప్పిన వాడు నరకానికి వెళతాడు, అక్కడ మీరు మీ చెడు చర్య యొక్క పరిణామాలను ఎదుర్కొంటారు.",
  "307": "పసుపు వస్త్రాన్ని ధరించే చాలా మంది వ్యక్తులు నీచంగా అదుపు చేయలేనివారుగా ఉంటారు. ఈ దుర్మార్గులు వారి దుష్ట క్రియల ఫలితంగా నరకంలో పుడతారు.",
  "308": "రాష్ట్ర ప్రయోజనాలను అనుభవిస్తూ దుర్మార్గంగా, నిరంకుశంగా జీవించడం కంటే ఎర్రగా వేడిచేసిన ఇనుప గుండును మింగడం మేలు.",
  "309": "మరొకరి భార్యతో సంబంధం పెట్టుకున్న వాడికి ఇవి జరుగుతాయి- దోష ప్రాప్తి, సుఖం లేని నిద్ర, నింద మరియు నరకం.",
  "310": "నిటారుగా వున్న పతనానికి దారి తీసే క్లుప్త ఆనందం కోసం, ప్రజలు వెళ్లరాని ప్రదేశాలలోకి చేరుకుంటారు. అధికారుల నుండి శిక్షను ఎదుర్కొ వలిసి వస్తోంది. మరొకరి భార్య గురించి ఆలోచించవద్దు.",
  "311": "గడ్డి పోచని తప్పుగా పట్టుకుంటే గీసుకొని రక్తం వస్తుంది. అలాగే ఆధ్యాత్మిక క్రమశిక్షణ తప్పుగా అనుసరిస్తే నరకానికి దారి తీస్తుంది.",
  "312": "అజాగ్రత్తగా చేసిన పని, సరిగ్గా పాటించని ప్రతిజ్ఞ, క్రమశిక్షణకు విధేయత చూపకపోవడం - ఇవన్నీ ఎటువంటి తీపి ఫలాన్ని ఇవ్వవు.",
  "313": "ఒక మనిషి తన పనిని సంకోచం లేకుండా చేసుకోవాలి. సరియైన క్రమశిక్షణ లేని సాధువు తన కలలన్ని బూడిద అవ్వడం చూస్తాడు.",
  "314": "ఒక చెడు పనిని వదిలివేయడం మంచిది, ఎప్పటికైనా ఆ పని బాధనే కలిగిస్తుంది; ఒక మంచి పని చేయడం మంచిది, ఎప్పటికి దాని వల్ల బాధ ఉండదు.",
  "315": "లోపలా, బయటా బాగా కాపలా ఉన్న సరిహద్దు పట్టణంలా మిమ్మల్ని మీరు కాపాడుకోండి. ఒక క్షణం కూడా అజాగ్రత్తగా జారిపోనివ్వవద్దు; ఎందుకంటే, నరకంలో పశ్చాత్తాపం తో ఏడుస్తారు.",
  "316": "అవమానానికి కారణం లేనప్పుడు అవమానంగా భావించే వారు మరియు సిగ్గుపడాల్సినప్పుడు సిగ్గుపడని వారు - ఇద్దరూ తప్పుడు సిద్ధాంతాలను అనుసరించి అధోముఖ మార్గంలో ప్రవేశిస్తారు.",
  "317": "భయానికి కారణం లేనప్పుడు భయపడే వారు మరియు భయపడాల్సినప్పుడు భయపడని వారు - ఇద్దరూ తప్పుడు సిద్ధాంతాలను అనుసరిస్తూ అధోముఖ మార్గంలోకి ప్రవేశిస్తారు.",
  "318": "చెడు లేని చోట చెడును గుర్తించే వారు మరియు చెడులో చెడు చూడని వారు - ఇద్దరూ తప్పుడు సిద్ధాంతాలను అనుసరిస్తూ అధోముఖ మార్గంలో ప్రవేశిస్తారు.",
  "319": "చెడును చెడుగా, చెడు లేనిది చెడు కాదని గుర్తించే వారు నిజమైన సిద్ధాంతాన్ని అనుసరించి మంచి మార్గంలో ప్రవేశిస్తారు.",
  "chap23": "ఏనుగులు",
  "320": "యుద్ధభూమిలో బాణాలతో కొట్టబడిన ఏనుగులాగా, నేను తిట్లను భరిస్తాను, ఎందుకంటే చాలా మంది ప్రజలు చెడు ప్రవర్తన కలిగి ఉన్నారు.",
  "321": "బాగా మచ్చిక చేసుకున్న జంతువును సమూహంలోకి నడిపిస్తారు; రాజు ఎక్కేది మచ్చిక చేసుకున్న ఏనుగునే; తిట్లను భరించే వ్యక్తి మనుషులలోకెల్లా ఉత్తముడు.",
  "322": "మంచి మచ్చిక చేసుకున్న మ్యూల్స్, సింధు ప్రాంతానికి చెందిన జాతి గుర్రాలు లేదా భారీ ఏనుగుల కంటే, తమను తాము మచ్చిక చేసుకున్న వారు ఉత్తములు.",
  "323": "ఎందుకంటే ఆ వాహనాలపై మీరు అడుగు పెట్టని ప్రదేశానికి వెళ్ళలేరు, అదే సమయంలో తమను తాము మచ్చిక చేసుకున్న వారి సహాయంతో, మచ్చిక చేయబడిన వారి ద్వారా మీరు అక్కడికి చేరుకుంటారు.",
  "324": "ధనపాల అనే పేరు గల ఏనుగు మదపు కాలంలో ఉండి, నియంత్రించడానికి కష్టంగా ఉంటుంది. బంధించబడినప్పుడు, అది ఏమీ తినదు, ఎందుకంటే అది ఏనుగుల అడవిని మిస్ అవుతుంది.",
  "325": "ఎక్కువగా తినడం వల్ల నిద్రమత్తుగా మారి, నిద్రకు ఇష్టపడుతూ, ధాన్యంతో నిండిన గొప్ప పందిలాగా మంచంపై దొర్లుతున్నవాడు: ఆ మూర్ఖుడు మళ్ళీ మళ్ళీ గర్భంలోకి తిరిగి వస్తాడు.",
  "326": "గతంలో నా మనస్సు తనకు నచ్చినట్లుగా, ఇష్టమైన చోట తిరిగింది. ఇప్పుడు నేను దానికి జాగ్రత్తగా మార్గనిర్దేశం చేస్తాను, మదపు ఏనుగును అంకుశంతో నడిపించే శిక్షకుడిలా.",
  "327": "శ్రద్ధలో ఆనందించండి! మీ మనస్సును జాగ్రత్తగా చూసుకోండి! బురదలో మునిగిపోయిన ఏనుగులాగా, ఈ గుంట నుండి మిమ్మల్ని మీరు బయటకు లాక్కోండి.",
  "328": "మీరు ఒక అప్రమత్తమైన తోడును, సంతోషంగా కలిసి జీవించడానికి ఒక శ్రద్ధగల స్నేహితుడిని కనుగొంటే, అప్పుడు అన్ని అడ్డంకులను అధిగమిస్తూ, వారితో ఆనందంగా మరియు అప్రమత్తంగా సంచరించండి.",
  "329": "మీరు ఎటువంటి అప్రమత్తమైన తోడును, కలిసి జీవించడానికి శ్రద్ధగల స్నేహితుడిని కనుగొనలేకపోతే, అప్పుడు జయించిన రాజ్యాన్ని విడిచిపెట్టే రాజులాగా, అడవుల్లో ఏనుగులాగా ఒంటరిగా సంచరించండి.",
  "330": "ఒంటరిగా సంచరించడం మంచిది, మూర్ఖులతో స్నేహం ఉండదు. ఒంటరిగా సంచరించండి మరియు తప్పు చేయకండి, అడవుల్లో ఏనుగులాగా హాయిగా ఉండండి.",
  "331": "అవసరమైనప్పుడు స్నేహితుడు దొరకడం ఒక వరం; దేనితోనైనా సంతృప్తి చెందడం ఒక వరం; జీవితాంతం మంచి పనులు చేయడం ఒక వరం; మరియు అన్ని బాధలను విడిచిపెట్టడం ఒక వరం.",
  "332": "ఈ ప్రపంచంలో తల్లిని, తండ్రిని సేవించడం ఒక వరం. మరియు సన్యాసులను, బ్రాహ్మణులను సేవించడం కూడా ఒక వరమే.",
  "333": "వృద్ధాప్యం వచ్చే వరకు నియమాలను పాటించడం ఒక వరం; విశ్వాసంలో స్థిరపడటం ఒక వరం; జ్ఞానాన్ని పొందడం ఒక వరం; మరియు తప్పు చేయడం మానుకోవడం ఒక వరం.",
  "chap24": "తృష్ణ",
  "334": "ఆలోచనలేని మనిషి యొక్క కోరిక, తాను చుట్టుకున్న చెట్టునే తినే మాలువ లతలా పెరుగుతుంది. గర్భం నుండి గర్భం వరకు అతను అడవిలో పండ్లు వెతుక్కునే కోతిలా తిరుగుతుంటాడు.",
  "335": "భయంకరమైన, విషపూరితమైన తృష్ణతో ఎవడు అయితే జీవిస్తున్నాడో, అతని దుఃఖం పుష్కలంగా ఉన్న బీరానా గడ్డిలా పెరుగుతుంది.",
  "336": "కానీ ఈ లోకంలో, అతి కష్టతరమైన తృష్ణను అధిగమించిన వ్యక్తి తన దుఃఖం, తామర ఆకు నుండి నీటి బిందువుల వలె రాలిపోతుంది.",
  "337": "ఇక్కడ గుమికూడిన మీ అందరికీ నేను చెప్తున్నాను - ఆశీర్వదించబడండి! తీపి-సువాసనగల ఉసిరా వేరు కోసం, బిరానా గడ్డిని తవ్వినట్లుగా, తృష్ణ యొక్క మూలాన్ని త్రవ్వండి. ఆ విధంగా గట్టి ప్రవాహము ఒడ్డున ఉన్న చెట్లను నాశనం చేసినట్లుగా మారా నిన్ను నాశనం చేయడు.",
  "338": "చెట్టుని నరికేసినప్పుడు, వేర్లనుండి ఏవిధంగా అయితే మళ్ళి పెరుగుతుందో, కోరిక యొక్క మూలాన్ని నాశనం చేయకపోతే జీవితంలోని బాధలు మళ్లీ మళ్లీ పెరుగుతాయి.",
  "339": "ఎవరిలో ముప్పై ఆరు ధారలు భోగభాగ్యాల వైపు పరిగెడతాయో, అతని ఆలోచనలు ఉద్రేకంలో స్థిరపడి, తప్పుడు దోవలోకి వెళ్తాడు. అతనికి తప్పుడు ఆలోచనలు, ఉద్దేశాలు ఉంటాయి.",
  "340": "కోరికల ధారలు ప్రతిచోటా ప్రవహిస్తాయి. కామం యొక్క లత మొలకెత్తి గట్టిగా మారుతుంది, ఆలా జరగడం గమనిస్తే, జ్ఞానంతో మూలాలను కత్తిరించండి.",
  "341": "సుఖాలు మరియు ఆనందాలు జీవులను ఆకర్షిస్తాయి. ఆ ఆనందాలను కౌగిలించుకొని మనుషులు వాటి వెనుక పరిగెడతారు. వారి వృద్ధాప్యం మరియు పునర్జన్మకు కారకం అవుతాయి.",
  "342": "తృష్ణతో వున్న మనుషులు వేటాడిన కుందేలులా పరిగెత్తుతారు. సంకెళ్ళు వేయబడిన వారు చాలా కాలం పాటు మళ్లీ మళ్లీ బాధలను అనుభవిస్తారు.",
  "343": "తృష్ణతో వున్న మనుషులు వేటాడిన కుందేలులా పరుగెత్తుతారు. కాబట్టి, స్వేచ్ఛ కోరుకునే వ్యక్తి కోరికను వదులుకోవాలి.",
  "344": "కోరికల అరణ్యం నుండి బయటికి వచ్చిన వాడు తిరిగి అక్కడికి వెళ్తాడు, కోరికల అడవి నుండి విముక్తి పొందినవాడు తిరిగి దాని వైపుకు పరిగెత్తుతాడు - వాడిని చూడండి, అతను స్వేచ్ఛగా ఉన్నప్పటికీ అతను బానిసత్వంలోకి ప్రవేశిస్తాడు.",
  "345": "తెలివైన వ్యక్తులు ఇనుము, కలప లేదా తాళ్లు వంటి వాటిని బలమైన గొలుసులుగా పరిగణించరు. బదులుగా ఆభరణాలు, విలువైన రాళ్ళు, కొడుకులు మరియు భార్యలు వంటి వాటిని బలమైన గొలుసులు అని వారు నమ్ముతారు.",
  "346": "సాధ్యమైనప్పటికీ, వాటి నుండి బయటపడటం కష్టం. ఎవరైనా ఈ బలమైన బంధాల నుండి విముక్తి పొందగలిగినప్పుడు, వారు తమ ప్రాపంచిక అనుబంధాలను విడిచిపెట్టి, వాటిని కోరుకోవడం మానేయాలి, ఇంద్రియాల ఆనందాలపై నివసించకుండా ఉండాలి.",
  "347": "తమ కోరికలకు బానిసలుగా మనుషులు, తాను వేసిన వలలోకే సాలీడు పరుగెత్తినట్లు ప్రవాహాల్లోకి పరుగెత్తుతారు. దృఢమైన వ్యక్తులు బంధాన్ని తెంచుకున్నప్పుడు ప్రపంచం నుండి విముక్తులవుతారు. అన్ని దుఃఖాలను విడిచిపెట్టి వెనుకకు చూడరు.",
  "348": "భవిష్యత్తు నుండి విముక్తి పొందండి; గతం నుండి విముక్తి పొందండి; వర్తమానంలో స్వేచ్ఛగా ఉండండి; అవతల ఒడ్డుకు చేరండి. పూర్తిగా స్వేచ్ఛగా ఉన్న మనస్సుతో మీరు జనన మరణాలలో పడరు.",
  "349": "చెదిరిన మనస్సులో కోరికలు పెరుగుతాయి, సుఖం కావాలనే కోరిక తలెత్తుతుంది. అందువలన సంకెళ్ళు బలంగా మారుతాయి.",
  "350": "తన చెదిరిన మనస్సును ప్రశాంతంగా ఉంచుకోవడంలో సంతోషించేవాడు మరియు కోరిక యొక్క అవాంఛనీయమైన స్వభావాన్ని దృష్టిలో ఉంచుకునేవాడు, అతను ఖచ్చితంగా మారా యొక్క బంధాన్ని తొలగిస్తాడు, నాశనం చేస్తాడు.",
  "351": "లక్ష్యాన్ని చేరుకున్నవాడు, నిర్భయుడు, కోరిక లేనివాడు, పాపం లేనివాడు, అతను జీవితంలోని అన్ని ముళ్ళను తొలగించాడు; ఇది అతని చివరి జీవితం.",
  "352": "తృష్ణ లేనివాడు, అనుబంధం లేనివాడు, అంతర్దృష్టితో కూడిన పదాలు మరియు వచనాలతో చొచ్చుకుపోయి, క్రమబద్ధతను తెలుసుకునేవాడు జ్ఞాని, గొప్ప వ్యక్తి. ఇదే అతని చివరి జీవితం.",
  "353": "'నేను అన్నింటినీ జయించాను. నాకు అన్నీ తెలుసు. నేను ఎలాంటి జీవన పరిస్థితిలోనైనా కలుషితం నుండి విముక్తి పొందాను. అన్నీ త్యజించాను. కోరికలన్నీ నశించినందున నేను స్వేచ్ఛగా ఉన్నాను. నేను వివేకంలోకి చొచ్చుకుపోయాను. అప్పుడు, నేను ఎవరి నుండి నేర్చుకున్నాను?'",
  "354": "ధర్మ దానం అన్ని బహుమతుల కంటే గొప్పది. న్యాయం యొక్క రుచి అన్ని రుచుల కంటే గొప్పది. ధర్మంలోని ఆనందం అన్ని ఆనందాల కంటే గొప్పది. తృష్ణ నశించడం బాధకు ముగింపు.",
  "355": "ఐశ్వర్యం మూర్ఖులను నాశనం చేస్తుంది, అది కోరుకోని వాడిని కాదు. మూర్ఖుడు తన ఆస్తి కోసం తృష్ణతో తనను తాను నాశనం చేసుకుంటాడు.",
  "356": "కలుపు మొక్కలు పొలాలకి శాపం. కామము మానవాళికి శాపము. అందుచేత దురభిమానం లేని వారికి ఇచ్చే బహుమతి గొప్ప ప్రతిఫలాన్ని తెస్తుంది.",
  "357": "కలుపు మొక్కలు పొలాలకి శాపం. ద్వేషం మానవాళికి శాపం. కావున ద్వేషం లేనివారికి ప్రసాదించిన బహుమతి గొప్ప ప్రతిఫలాన్ని తెస్తుంది.",
  "358": "కలుపు మొక్కలు పొలాలకి శాపం. భ్రమ మానవాళికి శాపం. కావున భ్రాంతి లేనివారికి ప్రసాదించిన బహుమానం గొప్ప ప్రతిఫలాన్ని తెస్తుంది.",
  "359": "కలుపు మొక్కలు పొలాలకి శాపం. కోరిక మానవజాతి యొక్క శాపం. కావున కోరికలు లేని వారికి ప్రసాదించిన బహుమతి గొప్ప ప్రతిఫలాన్ని తెస్తుంది.",
  "chap25": "భిక్షువు",
  "360": "మనం చూసే వాటి పట్ల జాగ్రత్తగా ఉండటం మంచిది. మనం విన్నదానితో జాగ్రత్తగా ఉండటం మంచిది.మన శరీరాన్ని జాగ్రత్తగా చూసుకోవడం మంచిది. మాటల విషయంలో జాగ్రత్తగా ఉండటం మంచిది.",
  "361": "మన ఆలోచనల పట్ల జాగ్రత్తగా ఉండటం మంచిది. ప్రతి విషయంలోనూ జాగ్రత్తగా ఉండటం మంచిది. ప్రతి విషయంలో జాగ్రత్తగా ఉండే సన్యాసి అన్ని బాధల నుండి విముక్తి పొందుతాడు.",
  "362": "అతని చేతులను, పాదాలను నియంత్రించే వాడిని భిక్షువు అని పిలవండి; తన ప్రసంగాన్ని ఎవరు నియంత్రిస్తారో; పూర్తిగా నియంత్రణలో ఉన్నవాడు; తనలో తాను సంతోషంగా ఉన్నవాడు; ఏకాంత జీవితంలో సంతృప్తంగా మరియు నిండుగా ఉండేవాడు భిక్షువు.",
  "363": "జ్ఞానం మాట్లాడే టప్పుడు తన నాలుకను జాగ్రత్తగా వాడేవాడు, ధర్మశాస్త్రంలోని అక్షరం మరియు ఆత్మ రెండింటినీ, పొంగిపోకుండా విశదీకరించే భిక్షువు యొక్క ఉపదేశం మధురమైనది.",
  "364": "ధర్మశాస్త్రాన్ని పాటించేవాడు, ధర్మశాస్త్రాన్ని ఆస్వాదించేవాడు, ధర్మశాస్త్రాన్ని ధ్యానించేవాడు, ధర్మశాస్త్రాన్ని బాగా గుర్తుంచుకునేవాడు - అటువంటి భిక్షువు ధర్మం నుండి తప్పిపోడు.",
  "365": "అతను అందుకున్నదానిని అతను అసహ్యించుకోకూడదు; అతను ఇతరులను చూసి అసూయపడకూడదు; ఇతరులను చూసి అసూయపడే భిక్కువు ధ్యానంలో శాంతిని పొందలేడు.",
  "366": "ఏ భిక్షువు అయితే తనకి దక్కిన దాంట్లో సంతోషంగా ఉంటాడో, ఎంత తక్కువగా ఉన్నప్పటికీ, శ్రమతో, స్వచ్ఛమైన జీవితాన్ని గడుపుతాడో, దేవతలు కూడా తనని మెచ్చుకుంటారు.",
  "367": "తన పేరు మరియు రూపం, తన మనస్సు మరియు శరీరంతో తన ఆత్మను గుర్తించని భిక్కువు, తనకు లేని వాటి కోసం దుఃఖించడు.",
  "368": "మెత్త, కరుణను అభ్యసించే వాడు, బుద్ధుని జ్ఞానంలో సంతోషంగా నివసించేవాడు, అతను ఉనికి ని కలిగి ఉండి, శాంతి పరమాత్మ యొక్క ఆశీర్వాద స్థితిని ఖచ్చితంగా పొందుతాడు.",
  "369": "ఓ భిక్కు, పడవను ఖాళీ చేయి; ఖాళీ చేసినప్పుడు అది తేలికగా వెళుతుంది. కామము మరియు దురాలోచనలను నరికివేయండి, అప్పుడు మీరు మోక్షమును చేరుకుంటారు.",
  "370": "ఐదింటిని కత్తిరించండి. ఆ ఐదింటిని విడిచెయ్యి. ఇంకా ఐదును సాగు చేయండి. ఈ విధంగా ఐదుసార్లు ప్రసవించిన భిక్కుని 'ఓఘతిన్నా' - 'ప్రళయాన్ని దాటినవాడు' అని పేరు పెట్టారు.",
  "371": "ధ్యానించు, ఓ భిక్కు; అజాగ్రత్తగా ఉండకు. మీ మనస్సు ఇంద్రియాలకు సంబంధించిన ఆనందాల చుట్టూ తిరగనివ్వకు. మీరు ఇనుప గుండును మింగవలసి వచ్చేలా నిర్లక్ష్యంగా ఉండకండి, ఆపై మండే నొప్పితో 'ఇది బాధ' అని కేకలు వేయకండి.",
  "372": "అంతర్దృష్టి లేకుండా ధ్యానం లేదు మరియు ధ్యానం లేకుండా అంతర్దృష్టి లేదు. అంతర్దృష్టి మరియు ధ్యానం రెండింటితో ఒకరు మోక్షాన్ని చేరుకుంటారు.",
  "373": "తన ఏకాంత ప్రదేశానికి వచ్చినప్పుడు, ప్రశాంతమైన మనస్సు మరియు ధర్మశాస్త్రం యొక్క సరైన వివేచన కలిగిన ఆ భిక్కు యొక్క ఆనందం మానవాతీతం.",
  "374": "అతను స్ఖ0ధాల చక్రాన్ని (వ్యక్తిగత జననం మరియు విచ్చిన్నం) పూర్తిగా గుర్తుంచుకుని, అర్థం చేసుకున్నప్పుడు, అతను ఆనందం మరియు ఆనందాన్ని అనుభవిస్తాడు. ఇది నిత్యజీవము.",
  "375": "ఇది తెలివైన భిక్కుకి ప్రారంభం: ఇంద్రియాల రక్షణ; సంతృప్తి; పతిమోఖ నియమాల ప్రకారం క్రమశిక్షణ; గొప్ప, స్వచ్ఛమైన మరియు ఉత్సాహవంతులైన స్నేహితుల ఎంపిక.",
  "376": "ఆతిథ్యం, దయ మరియు మర్యాదపూర్వకంగా ఉండనివ్వండి - తన విధులను నిర్వర్తించడంలో నైపుణ్యం కలగి ఉండనివ్వండి. అప్పుడు అతని ఆనందం, ఘనంగా ఉండటం వల్ల అతని బాధలు ముగిసిపోతాయి.",
  "377": "వాసిక మొక్క తన వాడిపోయిన పువ్వులను చిందించినట్లుగా, ఓ భిక్షువులారా, మీరు మోహాన్ని, దురభిమానాన్ని వదులుకోవాలి.",
  "378": "దేహశుద్ధి, వాక్కులో ప్రశాంతత, మనస్సులో ప్రశాంతత, దృఢంగా ఉంటూ, లోకంలోని ఎరలను పారద్రోలిన భిక్షువుకు 'శాంతిపరుడు' అని పేరు.",
  "379": "మీ స్వంత ప్రయత్నాల ద్వారా మిమ్మల్ని మేల్కొలపండి, స్వతహాగా మిమ్మల్ని మీరు అంచనా వేయండి. మిమ్మల్ని మీరు కాపాడుకుంటూ, బుద్ధిపూర్వకంగా ఉండడం ద్వారా, ఓ భిక్షూ, మీరు సంతృప్తిగా జీవిస్తారు.",
  "380": "నువ్వే నీ ప్రభువు; నువ్వే నీ ఆశ్రయం; కాబట్టి నిన్ను నువ్వు, ఒక వ్యాపారి చక్కటి గుర్రాన్ని అరికట్టినట్లు అరికట్టుకోవాలి.",
  "381": "భిక్కు ఆనందంతో సంతృప్తి చెంది, బుద్ధుని బోధనలపై విశ్వాసంతో, షరతులు లేని స్థితి - శాంతి యొక్క నిలయాన్ని పొందుతాడు.",
  "382": "బుద్ధుని బోధలను తనకు తాను అన్వయించుకునే యువ భిక్కు కూడా, మేఘం నుండి విడుదలైన చంద్రుని వలె ఈ ప్రపంచాన్ని ప్రకాశింపజేస్తాడు.",
  "chap26": "బ్రాహ్మణుడు",
  "383": "ఓ, బ్రాహ్మణా, శక్తితో నిండి ఉండు; కోరికల ప్రవాహాన్ని నిరోధించండి. విషయాలు ఎలా విచ్చిన్నమయిపోతాయో మీరు గ్రహించినప్పుడు, మీరు సృష్టించబడని బ్రహ్మాండాన్ని కూడా గ్రహిస్తారు.",
  "384": "ఒక బ్రాహ్మణుడు ధ్యానం మరియు అంతర్దృష్టి ద్వారా అవతలి ఒడ్డుకు చేరుకున్నప్పుడు అతను జ్ఞానాన్ని పొందుతాడు. అన్ని సంకెళ్ల నుండి విముక్తి పొందుతాడు.",
  "385": "ఈ తీరం మరియు అవతలి తీరం రెండింటికి అతీతంగా, నిర్భయంగా ముక్తి పొందిన వారిని నేను నిజమైన బ్రాహ్మణుడు అని పిలుస్తాను.",
  "386": "ధ్యానం లో స్థిరపడి; కర్తవ్యం పూర్తి చేసుకుని, దుర్మార్గాలు పోయి; స్థిరపడి, అత్యున్నతమైన ముగింపు సాధించిన వారు బ్రాహ్మణులు.",
  "387": "పగటిపూట సూర్యుడు ప్రకాశిస్తాడు; చంద్రుడు రాత్రి వెలిగుతాడు. యోధుడు (క్షత్రియుడు) తన కవచంలో మెరుస్తున్నాడు; బ్రాహ్మణుడు తన ధ్యానంలో మెరుస్తున్నాడు. కానీ బుద్ధుడు తన కీర్తిని ప్రసరింపజేస్తూ పగలు రాత్రి ప్రకాశిస్తాడు.",
  "388": "అతను పాపాన్ని తరిమికొట్టాడు కాబట్టి అతన్ని బ్రాహ్మణ అని పిలుస్తారు; అతను ప్రశాంతతలో నివసిస్తున్నాడు కాబట్టి అతన్ని సమాన అంటారు; అతను ప్రాపంచికతను దూరం చేసాడు కాబట్టి అతన్ని పబ్బాజిత అని పిలుస్తారు.",
  "389": "ఎవరూ బ్రాహ్మణుడిపై దాడి చేయకూడదు; బ్రాహ్మణుడు ప్రతీకారం తీర్చుకోకూడదు; బ్రాహ్మణుడిని కొట్టేవాడికి అరిష్టం, ప్రతీకారం తీర్చుకుంటే బ్రాహ్మణుడికి మరింత అరిష్టం.",
  "390": "జీవితం యొక్క ఆకర్షణల నుండి తన మనస్సును కాపాడినప్పుడు బ్రాహ్మణుడికి ఎటువంటి ప్రయోజనం ఉండదు. అంతేకాకుండా, హాని చేయాలనే ఉద్దేశ్యం ఆగిపోయినప్పుడు, ప్రత్యక్షంగా బాధల నుండి విముక్తి పొందుతారు.",
  "391": "శరీరం, మాట లేదా మనస్సు, ఈ మూడిటితో ఎవరిని అవమానించని వాడు బ్రాహ్మణుడు.",
  "392": "బ్రాహ్మణుడు యజ్ఞ అగ్నిని ఆరాధించినట్లే, సంపూర్ణ జ్ఞానోదయమైన వ్యక్తిని, ధర్మశాస్త్రాన్ని అర్థం చేసుకున్న వ్యక్తిని గౌరవించాలి.",
  "393": "తాళాల ద్వారా కాదు, వంశం ద్వారా, కులం ద్వారా కాడు బ్రాహ్మణుడు. తన సత్యం మరియు ధర్మం ద్వారా మనిషి బ్రాహ్మణుడు అవుతాడు. అతడు ధన్యుడు.",
  "394": "ఓ మూర్ఖుడా, నీ జడలు కట్టిన జుట్టుతో ఎం లాభం? నీ జింక చర్మం దేనికి ఉపయోగకరం, బాహ్యంగా నిన్ను నువ్వు శుభ్రపరుచుకుంటావు, నీ లోపల ఆవేశం ఉంది.",
  "395": "ఎవరైనా అడవిలో ఒంటరిగా ఉండి, లోతుగా ధ్యానం చేస్తూ, సన్నని శరీరం, నరాలు, రక్తనాళాలు కనబడుతూ, పాత గుడ్డతో కప్పబడి ఉంటే నేను నిజమైన బ్రాహ్మణుడు అని పిలుస్తాను.",
  "396": "ఇది వారి పుట్టుక లేదా కుటుంబంతో సంబంధం లేదు.",
  "397": "ధనవంతుడుగా ఉన్నప్పటికీ, నిర్లిప్తంగా, ఆస్తులు లేకపోయినా ఉన్నచో, వారు నిజమైన బ్రాహ్మణులు.",
  "398": "అన్ని సంకెళ్లను నాశనం చేసి, భయపడాల్సిన అవసరం లేని, విముక్తి పొందిన వాడు బ్రాహ్మణుడు.",
  "399": "ద్వేషం అనే పట్టీలను, తృష్ణను, మతోన్మాదుల తాడును, అవ్యక్త ధోరణుల అనుబంధాన్ని తెంచుకుని, అజ్ఞానపు బారిని పగలగొట్టి, మేల్కొన్న వాడు బ్రాహ్మణుడు.",
  "400": "అతను అన్ని నేరాలకు నిర్దోషి అయినప్పటికీ నిందలు, దుర్మార్గం మరియు నిర్బంధాన్ని ఓపికగా భరించాడు. సహనం అతని శక్తి, అతని స్వంత బలం అతని సైన్యం.",
  "401": "కోపము లేనివాడు, కర్తవ్యాలకు అంకితమైనవాడు, దైవిక ధర్మాలను ఆచరించేవాడు, కోరికలు లేనివాడు మరియు నియంత్రణలో ఉండేవాడు బ్రాహ్మణుడు. అతను తన చివరి శరీరాన్ని ధరించాడు.",
  "402": "ఎవరి కోరికలు అయితే తామర ఆకు నుండి నీటి బిందువు రాలి నట్టు రాలుతాయో వాడు బ్రాహ్మణుడు.",
  "403": "ఇక్కడ కూడా, తన బాధలకు ముగింపు ఉంటుంది అని తెలుసుకున్న వాడు, తన భారాన్ని పక్కనపెట్టి, నిర్లిప్తంగా ఉన్నవాడిని బ్రాహ్మణుడని పిలుస్తాను.",
  "404": "ఎవరి జ్ఞానం అయితే లోతైనదో, ఎవరు అయితే సరైన మార్గం, తప్పుడు మార్గం మధ్య తేడా తెలిసి ఉంటారో వారు బ్రాహ్మణులు.",
  "405": "గృహస్థులతో లేదా సన్యాసులతో సన్నిహితంగా ఉండని మరియు తరచుగా ఇళ్లకు వెళ్లని వాడు బ్రాహ్మణుడు.",
  "406": "ఎవరు అయితే తన కర్రని దూరంగా ఉంచుతాడో, దేనిని చంపని వాడు, బలహీనమైన, బలమైన ఏ ప్రాణిని చంపడానికి కారణం కానీ వాడు బ్రాహ్మణుడు.",
  "407": "విరోధుల మధ్య స్నేహంగా ఉండేవాడు, హింసించేవారిలో సౌమ్యుడు, అత్యాశపరుల మధ్య అతీతుడు అయిన వాడు బ్రాహ్మణుడు.",
  "408": "ఎవరైతే కామం, దురభిమానం, అహంకారం ని ఆవగింజ రాలిపోయినట్టు త్యజిస్తాడో, అతడు బ్రాహ్మణుడు.",
  "409": "ఎవరి ప్రసంగం అయితే సత్యమైనది, సౌమ్యమైనది, బోధించేది, ఎవరినీ కించపరచనిదో అతడు బ్రాహ్మణుడు.",
  "410": "అతనికి ఇవ్వనిదేదీ తీసుకోని వాడిని బ్రాహ్మణుడని నేను పిలుస్తాను, అది చిన్నది కానీ పెద్దది కానీ, మంచిది కానీ చెడుది కానీ.",
  "411": "అతనికి చేపట్టుకోవడం లేనిది, జ్ఞానం సంశయానికి నుండి విముక్తి చేసినవాడు, లక్ష్యానికి చేరుకున్నవాడు, మరణం నుండి విముక్తితోఅతనిని నేను బ్రాహ్మణుడని పిలుస్తాను.",
  "412": "ఇహలోకానికి లేదా పరలోకానికి సంబంధించిన కోరికలు లేని, వాంఛలు లేని మరియు సంకెళ్ళు లేని వాడు బ్రాహ్మణుడు.",
  "413": "కోరికలు లేనివాడు, జ్ఞానంతో తన సందేహాలను నాశనం చేసినవాడు మరియు శాశ్వతాన్ని చూసినవాడు బ్రాహ్మణుడు.",
  "414": "యోగ్యత మరియు దోషాల బంధాలకు అతీతుడు, దుఃఖం లేనివాడు, మోహము లేనివాడు, పవిత్రుడు అయిన వాడు బ్రాహ్మణుడు.",
  "415": "చంద్రుడిలా స్వచ్ఛమైన, నిర్మలమైన మరియు స్పష్టమైన వాడు బ్రాహ్మణుడు, ఉనికిలో ఆనందించని వాడు బ్రాహ్మణుడు. (గమనిక: ఈ సంఖ్యలు పునరావృతమయ్యాయి).",
  "416": "పునర్జన్మ మరియు భ్రాంతి యొక్క రహదారిని దాటి అవతలి ఒడ్డుకు చేరుకున్నవాడు; ధ్యానం చేసేవాడు, సందేహం లేనివాడు, అనుబంధం లేనివాడు, ప్రశాంతంగా మరియు సంతృప్తిగా ఉండేవాడు బ్రాహ్మణుడు.",
  "417": "వస్తువులపై ఉన్న అనుబంధం యొక్క కాడిని తెంచుకున్న, సుఖం కలిగించే వాటి పై ఉన్న అనుబంధాన్ని అధిగమించి, అన్ని అనుబంధాలను అధిగమించిన వాడు బ్రాహ్మణుడు.",
  "418": "బ్రాహ్మణుడు ఎవరు అంటే, ఇష్టాలు మరియు అయిష్టాలు లేనివాడు, శాంతంగా ఉండేవాడు, పునర్జన్మల చక్రం నుండి విముక్తి పొంది, లోకములను జయించిన వీరుడు బ్రాహ్మణుడు.",
  "419": "అన్ని జీవుల మరణం మరియు పునర్జన్మ యొక్క రహస్యాన్ని తెలిసినవాడు, అనుబంధం లేనివాడు, తనలో తాను సంతోషంగా ఉన్నవాడు మరియు జ్ఞానోదయం కలిగిన వాడు బ్రాహ్మణుడు.",
  "420": "బ్రాహ్మణుడు ఎవరు అంటే, అతని నిజమైన స్థితి దేవతలకి, గంధర్వులకి లేదా మనుషులకి తెలియని వాడు. అతని దుర్మార్గాలు నాశనం చేయబడి, అతను అర్హత్ అయ్యాడు.",
  "421": "భూతానికి, వర్తమానానికి, భవిష్యత్తుకు సంబంధించి తనకంటూ ఏమీ లేని, స్వాధీనత లేని, నిర్లిప్తుడైన వాడు బ్రాహ్మణుడు.",
  "422": "వృషభమువంటి నిర్భయము కలవాడు, శ్రేష్ఠుడు మరియు ధైర్యసాహసాలు ఉన్నవాడు, జ్ఞాని అయినవాడు, మృత్యువును కూడా జయించినవాడు, పాపరహితుడు, జ్ఞానోదయం కలిగిన వాడిని బ్రాహ్మణుడు అని పిలుస్తాను.",
  "423": "అతని పూర్వజన్మలను తెలిసినవాడు, స్వర్గ నరకాలను తెలిసినవాడు, జన్మాంతరానికి చేరుకున్నవాడు, పరిపూర్ణమైన జ్ఞానము గలవాడు మరియు సాధించవలసినదంతా సాధించినవాడు బ్రాహ్మణుడు."
};
